return ['domain'=>'agnosis','plural-forms'=>'nplurals=6; plural=n==0 ? 0 : n==1 ? 1 : n==2 ? 2 : n%100 >= 3 && n%100<=10 ? 3 : n%100 >= 11 && n%100<=99 ? 4 : 5;','language'=>'ar','project-id-version'=>'Agnosis 0.9.21','pot-creation-date'=>'2026-07-12T16:27+00:00','po-revision-date'=>'2026-07-12 17:20+0000','x-generator'=>'Loco https://localise.biz/','messages'=>['Agnosis'=>'Agnosis','https://agnosis.art'=>'https://agnosis.art','Art blooming out of oblivion. Email your art, AI polishes it, the world sees it. A free, federated publishing network for independent artists.'=>'فنّ يزهر من رحم النسيان. أرسل فنّك عبر البريد الإلكتروني، يلمّعه الذكاء الاصطناعي، فيراه العالم. شبكة نشر مجانية ولا مركزية للفنانين المستقلين.','Agnosis Network'=>'شبكة Agnosis','Agnosis requires PHP %s or higher.'=>'يتطلب Agnosis إصدار PHP %s أو أحدث.','Agnosis requires WordPress %s or higher.'=>'يتطلب Agnosis إصدار WordPress %s أو أحدث.','Filter by medium'=>'تصفية حسب الوسيط','All'=>'الكل','Enlarged image'=>'صورة مكبّرة','Featured'=>'مميّز','Enlarge'=>'تكبير','Gallery pages'=>'صفحات المعرض','Prev'=>'السابق','Next'=>'التالي','Contact Messages'=>'رسائل التواصل','No contact messages yet.'=>'لا توجد رسائل تواصل بعد.','No messages match this filter.'=>'لا توجد رسائل تطابق هذا التصفية.','#'=>'#','Artist'=>'الفنان','From'=>'من','Message'=>'الرسالة','Status'=>'الحالة','Received'=>'تاريخ الاستلام','Actions'=>'الإجراءات','(deleted artist #%d)'=>'(الفنان المحذوف رقم #%d)','You do not have permission to perform this action.'=>'ليس لديك إذن لتنفيذ هذا الإجراء.','Message deleted.'=>'تم حذف الرسالة.','All statuses'=>'جميع الحالات','Sent'=>'مُرسلة','Rejected'=>'مرفوضة','Filter'=>'تصفية','Reset'=>'إعادة الضبط','Page %1$d of %2$d'=>'الصفحة %1$d من %2$d','Previous'=>'السابق','Delete this message?'=>'هل تريد حذف هذه الرسالة؟','Delete'=>'حذف','just now'=>'الآن للتو','%dm ago'=>'منذ %d دقيقة','%dh ago'=>'منذ %d ساعة','Mail from (workflow)'=>'Mail from (workflow)','Newsletter'=>'النشرة الإخبارية','Agnosis Inbox'=>'صندوق وارد Agnosis','Inbox'=>'صندوق الوارد','No messages in the queue yet. Click "Poll Inbox" to fetch messages from your IMAP account.'=>'لا توجد رسائل في قائمة الانتظار بعد. انقر على "Poll Inbox" لجلب الرسائل من حساب IMAP الخاص بك.','No queue rows match this filter.'=>'لا توجد صفوف في قائمة الانتظار تطابق هذا التصفية.','Subject'=>'الموضوع','Endpoint'=>'نقطة النهاية','Files'=>'الملفات','Error'=>'خطأ','unregistered sender'=>'مرسل غير مسجّل','Old row — delete and re-poll to preview'=>'السطر القديم — احذفه وأعد الاستطلاع للمعاينة','Attachment viewer'=>'عارض المرفقات','Close'=>'إغلاق','Queue row deleted. Poll Inbox to re-fetch the message.'=>'تم حذف صف قائمة الانتظار. استطلع صندوق الوارد لجلب الرسالة مرة أخرى.','Queue #%d sent to pipeline. Check back in a few seconds.'=>'تم إرسال قائمة الانتظار #%d إلى خط المعالجة. تحقق مرة أخرى بعد بضع ثوانٍ.','Poll complete. %d new message(s) added to the queue.'=>'اكتمل الاستطلاع. تمت إضافة %d رسالة/رسائل جديدة إلى قائمة الانتظار.','Force-reprocess: %1$d row(s) reset, %2$d new message(s) enqueued.'=>'إعادة المعالجة القسرية: تمت إعادة تعيين %1$d صف/صفوف، وتمت إضافة %2$d رسالة/رسائل جديدة إلى قائمة الانتظار.','Processed %d pending item(s).'=>'تمت معالجة %d عنصر/عناصر قيد الانتظار.','Pending'=>'قيد الانتظار','Processing'=>'جارٍ المعالجة','Published'=>'منشور','Failed'=>'فشل','Skipped'=>'تم التخطي','All reasons'=>'كل الأسباب','%1$d message from an unregistered sender is hidden from this view. <a href="%2$s">View it</a>.'=>'تم إخفاء رسالة واحدة من مرسل غير مسجل من هذا العرض. <a href="%2$s">عرضها</a>.' . "\0" . 'تم إخفاء %1$d رسالة من مرسلين غير مسجلين من هذا العرض. <a href="%2$s">عرضها</a>.' . "\0" . '' . "\0" . '' . "\0" . '' . "\0" . '','Poll Inbox'=>'استطلاع صندوق الوارد','Force Reprocess'=>'إعادة المعالجة القسرية','Process All Pending'=>'معالجة كل العناصر قيد الانتظار','Goodbye'=>'مع السلامة','Community'=>'المجتمع','Bounce'=>'ارتداد','Awaiting Review'=>'بانتظار المراجعة','Live'=>'مباشر','Processed'=>'تمت المعالجة','Member Removed'=>'تمت إزالة العضو','Broadcast Sent'=>'تم إرسال البث','Bounced (too long)'=>'ارتدّ (طويل جدًا)','Handled'=>'تم التعامل معه','Process'=>'معالجة','View Post'=>'عرض المنشور','Reprocess'=>'إعادة المعالجة','Running…'=>'جارٍ التشغيل…','Delete this queue row?'=>'هل تريد حذف صف قائمة الانتظار هذا؟','Configuration'=>'الإعدادات','Force-reprocess complete. %1$d queue row(s) reset, %2$d new message(s) enqueued. Click "Process Pending Queue" to run the AI pipeline.'=>'اكتملت إعادة المعالجة القسرية. تمت إعادة تعيين %1$d صف/صفوف من قائمة الانتظار، وتمت إضافة %2$d رسالة/رسائل جديدة إلى قائمة الانتظار. انقر "معالجة قائمة الانتظار قيد الانتظار" لتشغيل خط أنابيب الذكاء الاصطناعي.','Log cleared.'=>'تم مسح السجل.','Debug files cleared. %d file was removed.'=>'تم مسح ملفات التصحيح. تمت إزالة %d ملف.' . "\0" . 'تم مسح ملفات التصحيح. تمت إزالة %d ملفات.' . "\0" . '' . "\0" . '' . "\0" . '' . "\0" . '','Term translation cache cleared. Terms will be re-translated the next time they\'re needed.'=>'تم مسح ذاكرة التخزين المؤقت لترجمة المصطلحات. ستتم إعادة ترجمة المصطلحات عند الحاجة إليها مرة أخرى.','Processed %d pending queue item(s). Check the Logs tab for details.'=>'تمت معالجة %d عنصر/عناصر من قائمة الانتظار قيد الانتظار. راجع علامة تبويب السجلات للتفاصيل.','Poll complete. %d new message(s) enqueued. Check the Logs tab, then click Process Pending Queue.'=>'اكتمل الاستطلاع. تمت إضافة %d رسالة/رسائل جديدة إلى قائمة الانتظار. راجع علامة تبويب السجلات، ثم انقر "معالجة قائمة الانتظار قيد الانتظار".','Applicant admitted. A welcome email has been sent.'=>'تم قبول المتقدم. تم إرسال رسالة ترحيب بالبريد الإلكتروني.','Could not admit — the application may no longer be pending.'=>'تعذّر قبول المتقدم — قد لا يكون الطلب قيد الانتظار بعد الآن.','Application rejected.'=>'تم رفض الطلب.','Could not reject — the application may no longer be pending.'=>'تعذّر رفض الطلب — قد لا يكون الطلب قيد الانتظار بعد الآن.','Artist suspended. A notification email has been sent.'=>'تم تعليق الفنان. تم إرسال رسالة إشعار بالبريد الإلكتروني.','Could not suspend the artist — they may no longer be active.'=>'تعذّر تعليق الفنان — قد لا يكون نشطًا بعد الآن.','Artist permanently deleted. Their account and all content have been removed.'=>'تم حذف الفنان نهائيًا. تمت إزالة حسابه وكل المحتوى.','Could not delete the artist — please try again.'=>'تعذّر حذف الفنان — يُرجى المحاولة مرة أخرى.','Community removal vote opened. All artists have been emailed.'=>'تم فتح تصويت لإزالة من المجتمع. تم إرسال بريد إلكتروني إلى جميع الفنانين.','Could not open a removal vote — one may already be active for this artist.'=>'تعذّر فتح تصويت للإزالة — قد يكون هناك تصويت نشط بالفعل لهذا الفنان.','Issue prepared and queued — it will go out over the next few cron cycles.'=>'تمت تهيئة العدد وإدراجه في قائمة الانتظار — سيُرسل خلال بضع دورات كرون القادمة.','Could not start this issue — a previous one may still be sending.'=>'تعذّر بدء هذا العدد — قد يكون عدد سابق لا يزال قيد الإرسال.','Test email sent — check the inbox you sent it to.'=>'تم إرسال رسالة الاختبار — تحقّق من صندوق الوارد الذي أرسلتها إليه.','Could not send the test email — check the address and your site\'s outgoing mail configuration.'=>'تعذّر إرسال رسالة الاختبار — تحقّق من العنوان ومن إعدادات البريد الصادر لموقعك.','Invitation sent.'=>'تم إرسال الدعوة.','Could not send the invitation — check the address and your site\'s outgoing mail configuration.'=>'تعذّر إرسال الدعوة — تحقّق من العنوان ومن إعدادات البريد الصادر لموقعك.','Test invitation sent — check the inbox you sent it to.'=>'تم إرسال دعوة الاختبار — تحقّق من صندوق الوارد الذي أرسلتها إليه.','Could not send the test invitation — check the address and your site\'s outgoing mail configuration.'=>'تعذّر إرسال دعوة الاختبار — تحقّق من العنوان ومن إعدادات البريد الصادر لموقعك.','Test email sent — check whether it lands in your inbox or your spam folder.'=>'تم إرسال رسالة الاختبار — تحقّق مما إذا كانت تصل إلى صندوق الوارد أو إلى مجلد البريد المزعج.','Failed recipients reset to pending — they will be retried on the next few cron cycles.'=>'تمت إعادة تعيين المستلمين الذين فشلوا إلى «قيد الانتظار» — وسيُعاد المحاولة خلال بضع دورات كرون القادمة.','No failed recipients to retry for this newsletter.'=>'لا يوجد مستلمون فشلوا لإعادة المحاولة لهذه النشرة الإخبارية.','Art blooming out of oblivion'=>'فنّ يزهر من غياهب النسيان','Save Changes'=>'حفظ التغييرات','Members'=>'الأعضاء','Rules'=>'القواعد','General'=>'عام','Email Inbox'=>'صندوق الوارد للبريد الإلكتروني','AI Providers'=>'مزوّدو الذكاء الاصطناعي','Behavior'=>'السلوك','Network'=>'الشبكة','Commerce'=>'التجارة','Logs'=>'السجلات','— None (inline message only) —'=>'— لا شيء (رسالة مضمّنة فقط) —','Reset to default'=>'إعادة الضبط إلى الافتراضي','Replaces the text above with the plugin\'s built-in default — click Save Changes below to keep it.'=>'يستبدل النص أعلاه بالافتراضي المدمج في الإضافة — انقر «حفظ التغييرات» أدناه للاحتفاظ به.','Select Image'=>'اختيار صورة','Remove'=>'إزالة','Base domain'=>'النطاق الأساسي','Root domain for artist subdomains, e.g. agnosis.art. Each artist is reachable at nicename.{base_domain}. Requires a wildcard DNS record (*.{base_domain}) pointing to this server. Leave blank to disable subdomain routing.'=>'النطاق الجذر لنطاقات الفنانين الفرعية، مثل agnosis.art. يمكن الوصول إلى كل فنان على nicename.{base_domain}. يتطلب سجل DNS شاملًا (*.{base_domain}) يشير إلى هذا الخادم. اتركه فارغًا لتعطيل توجيه النطاقات الفرعية.','Debug logging'=>'تسجيل التصحيح','Writes raw diagnostic dumps of the email intake pipeline (message structure, attachment MIME detection, media conversion, post creation) to a dedicated debug directory — far more detail than the Logs tab keeps, for tracing exactly where a submission was rejected or lost. Turn off once you have what you need; files can accumulate quickly. Can also be forced from wp-config.php with `define( \'AGNOSIS_DEBUG\', true );`, which overrides this toggle. See the Debug Files panel below for the directory location and a clear-files button.'=>'يكتب تفريغات تشخيصية خامًا لخط أنابيب إدخال البريد الإلكتروني (بنية الرسالة، واكتشاف MIME للمرفقات، وتحويل الوسائط، وإنشاء المقال) إلى دليل تصحيح مخصص — بتفاصيل أكبر بكثير مما يحتفظ به تبويب السجلات، لتتبّع المكان الذي رُفضت فيه الإرسالية أو فُقدت. أوقفه بمجرد أن تحصل على ما تحتاجه؛ فقد تتراكم الملفات بسرعة. يمكن أيضًا فرضه من wp-config.php باستخدام `define( \'AGNOSIS_DEBUG\', true );`، والذي يتجاوز هذا الخيار. راجع لوحة ملفات التصحيح أدناه لمعرفة موقع الدليل وزر لمسح الملفات.','Debug file retention (days)'=>'مدة الاحتفاظ بملفات التصحيح (بالأيام)','Debug dumps older than this are permanently deleted by the daily cleanup — automatically, whether or not debug logging is currently turned on, so files left over from a past debug session don\'t linger indefinitely. A dump is a full raw copy of an artist\'s email, so this defaults shorter than the inbox/queue retention above. Default: 14 days.'=>'تُحذف تفريغات التصحيح الأقدم من هذه المدة نهائيًا بواسطة التنظيف اليومي — تلقائيًا، سواء كان تسجيل التصحيح مفعّلًا حاليًا أم لا، حتى لا تبقى الملفات المتروكة من جلسة تصحيح سابقة إلى ما لا نهاية. التفريغ هو نسخة خام كاملة من رسالة بريد الفنان، لذا فإن القيمة الافتراضية أقصر من مدة الاحتفاظ بصندوق الوارد/قائمة الانتظار أعلاه. الافتراضي: 14 يومًا.','Email logo'=>'شعار البريد الإلكتروني','Shown in the header of outgoing HTML emails (submission review, removal confirmation, rejection notice, and both newsletters) in place of the plain "✦ Site Name" text. Leave empty to keep the text wordmark. Displayed at up to 40px tall — any width or aspect ratio works.'=>'يُعرض في ترويسة رسائل HTML الصادرة (مراجعة الإرسال، تأكيد الإزالة، إشعار الرفض، وكلا النشرتين الإخباريتين) بدلًا من النص البسيط "✦ اسم الموقع". اتركه فارغًا للإبقاء على العلامة النصية. يُعرض بارتفاع يصل إلى 40px — أي عرض أو نسبة أبعاد يعمل.','Preset biography title'=>'عنوان السيرة الذاتية المسبق','When set, every artist\'s biography page uses this exact title instead of their own, regardless of what the artist submitted, edited on their approve form, or later changed on their published page. Leave blank to keep using each artist\'s own title (the default). Shown exactly as typed here on every language version of a biography page — not machine-translated per language. See "Include artist\'s name in preset title" below.'=>'عند ضبطه، تستخدم صفحة السيرة الذاتية لكل فنان هذا العنوان بالضبط بدلًا من عنوانه الخاص، بغضّ النظر عمّا أرسله الفنان أو عدّله في نموذج الموافقة أو غيّره لاحقًا في صفحته المنشورة. اتركه فارغًا للاستمرار في استخدام عنوان كل فنان الخاص (الافتراضي). يُعرض هنا كما كُتب تمامًا في كل نسخة لغوية من صفحة السيرة الذاتية — وليس مترجمًا آليًا حسب اللغة. راجع «تضمين اسم الفنان في العنوان المسبق» أدناه.','Include artist\'s name in preset title'=>'تضمين اسم الفنان في العنوان المسبق','When the preset title above is set, append the artist\'s own WordPress display name to it (e.g. "Meet the Artist — Jane Doe"). Has no effect while the preset title is blank.'=>'عند ضبط العنوان المسبق أعلاه، يُضاف اسم العرض الخاص بالفنان في ووردبريس إليه (مثلًا: "Meet the Artist — Jane Doe"). لا يكون له أي تأثير ما دام العنوان المسبق فارغًا.','Cloudflare Turnstile site key'=>'مفتاح موقع Cloudflare Turnstile','From your Cloudflare Turnstile widget (dash.cloudflare.com → Turnstile). Adds a human-verification check to the public Subscribe (newsletter-signup) and Join forms. Leave either key blank to leave both forms exactly as they are today.'=>'من أداة Cloudflare Turnstile الخاصة بك (dash.cloudflare.com → Turnstile). يضيف فحص تحقق بشري إلى نموذجي الاشتراك العام (newsletter-signup) والانضمام. اترك أيًا من المفتاحين فارغًا للإبقاء على النموذجين كما هما الآن.','Cloudflare Turnstile secret key'=>'المفتاح السري لـ Cloudflare Turnstile','Kept server-side only — used to verify each form submission directly with Cloudflare before it is accepted.'=>'يُحفظ من جهة الخادم فقط — ويُستخدم للتحقق من كل عملية إرسال نموذج مباشرةً مع Cloudflare قبل قبولها.','Email driver'=>'مُشغّل البريد الإلكتروني','Artwork submissions address'=>'عنوان إرسال الأعمال الفنية','Artists send artwork to this address — e.g. submit@agnosis.art'=>'يرسل الفنانون الأعمال الفنية إلى هذا العنوان — مثلًا: submit@agnosis.art','Biography submissions address'=>'عنوان إرسال السيرة الذاتية','Artists send biography updates to this address — e.g. bio@agnosis.art'=>'يرسل الفنانون تحديثات السيرة الذاتية إلى هذا العنوان — مثلًا: bio@agnosis.art','Event submissions address'=>'عنوان إرسال الفعاليات','Artists send event announcements to this address — e.g. event@agnosis.art'=>'يرسل الفنانون إعلانات الفعاليات إلى هذا العنوان — مثلًا: event@agnosis.art','Replace artwork address'=>'عنوان بريد استبدال العمل الفني','Artist sends a new version of an existing artwork. Subject must match the original title. Bypasses duplicate detection — e.g. replace@agnosis.art'=>'يرسل الفنان نسخة جديدة من عمل فني موجود. يجب أن يطابق الموضوع العنوان الأصلي. يتجاوز اكتشاف التكرار — مثلًا: replace@agnosis.art','Removal request address'=>'عنوان طلب الإزالة','Artist requests takedown of an existing artwork. Subject must match the title. Moves the post to draft pending admin review — e.g. remove@agnosis.art'=>'يطلب الفنان إزالة عمل فني موجود. يجب أن يطابق الموضوع العنوان. ينقل المنشور إلى المسودات بانتظار مراجعة المدير — مثلًا: remove@agnosis.art','Promote artwork address'=>'عنوان ترويج العمل الفني','Artist sends an email here (subject = exact artwork title) to choose which artwork represents them in the shared community gallery on the main site — not their own subdomain, which already shows everything they\'ve published. Any previously featured artwork is automatically demoted — e.g. promote@agnosis.art'=>'يرسل الفنان بريدًا إلكترونيًا إلى هنا (الموضوع = العنوان الدقيق للعمل الفني) لاختيار أي عمل فني يمثّله في معرض المجتمع المشترك على الموقع الرئيسي — وليس نطاقه الفرعي الخاص، الذي يعرض بالفعل كل ما نشره. أي عمل فني كان مميزًا سابقًا يُخفَّض تلقائيًا — مثلًا: promote@agnosis.art','Photo-only address'=>'عنوان خاص بالصور فقط','Opt-out lane for photographers and lens-based artists whose photograph is the artwork, not a snapshot of it. Submissions here are published with the original image exactly as sent — AI enhancement is skipped and the quality-rejection gate is bypassed. AI description (title, tags, alt text) still runs. Use the [Photo] subject indicator as a fallback for mail clients that do not support To: aliases — e.g. photo@agnosis.art'=>'مسار استثناء للمصورين والفنانين المعتمدين على العدسات، حيث تكون الصورة نفسها هي العمل الفني، لا لقطة لها. تُنشر الإرسالات هنا بالصورة الأصلية تمامًا كما أُرسلت — يتم تخطي تحسين الذكاء الاصطناعي وتجاوز بوابة رفض الجودة. كما يستمر تشغيل وصف الذكاء الاصطناعي (العنوان، الوسوم، النص البديل). استخدم مؤشر الموضوع [Photo] كبديل احتياطي لعملاء البريد التي لا تدعم أسماء To: المستعارة — مثلًا: photo@agnosis.art','Pure address (no AI at all)'=>'عنوان خالص (من دون ذكاء اصطناعي على الإطلاق)','Strictest opt-out lane: nothing sent here is touched by AI — no enhancement, no vision description, no rewriting. The published post title, body, and translated-title subtitle are taken verbatim from the artist\'s own subject and message text; the attached file(s) are published exactly as sent. The quality-rejection gate is bypassed, same as Photo-only. Use the [Pure] subject indicator as a fallback for mail clients that do not support To: aliases — e.g. pure@agnosis.art'=>'أشد مسارات الاستثناء تقييدًا: لا يلمس الذكاء الاصطناعي أي شيء يُرسل هنا — لا تحسين، لا وصف بصري، لا إعادة صياغة. يُؤخذ عنوان المنشور المنشور، ونصه، وتسمية العنوان المترجَم الفرعية حرفيًا من موضوع الفنان ونص رسالته؛ وتُنشر الملفات المرفقة تمامًا كما أُرسلت. يتم تجاوز بوابة رفض الجودة، تمامًا مثل وضع الصور فقط. استخدم مؤشر الموضوع [Pure] كبديل احتياطي لعملاء البريد التي لا تدعم أسماء To: المستعارة — مثلًا: pure@agnosis.art','Goodbye / self-removal address'=>'عنوان الوداع / الحذف الذاتي','Artist emails here (any subject, no attachment needed) to request account deletion. A confirmation link is emailed back before anything is deleted — e.g. goodbye@agnosis.art'=>'يرسل الفنان بريدًا هنا (أي موضوع، ولا حاجة إلى مرفق) لطلب حذف الحساب. يُرسل رابط تأكيد عبر البريد قبل حذف أي شيء — مثلًا: goodbye@agnosis.art','Community announcement address'=>'عنوان إعلان المجتمع','Any active artist emails here (any subject, no attachment needed) to send a message to every other community member — e.g. community@agnosis.art. Never processed as a submission and never becomes a post: each recipient gets the subject and message translated into their own language, with the sender\'s name and email included so they can reply directly. Sent from the address configured under Settings → Community → Rules, which can be different from this one. Only works for a message sent by an active, admitted artist.'=>'يمكن لأي فنان نشط أن يرسل بريدًا هنا (أي موضوع، ولا حاجة إلى مرفق) لإرسال رسالة إلى كل عضو آخر في المجتمع — مثلًا: community@agnosis.art. لا تُعالج أبدًا كإرسال ولا تصبح منشورًا: يتلقى كل مستلم الموضوع والرسالة مترجمين إلى لغته الخاصة، مع تضمين اسم المرسل وبريده الإلكتروني ليتمكن من الرد مباشرة. تُرسل من العنوان المكوَّن ضمن الإعدادات → المجتمع → القواعد، وقد يختلف عن هذا العنوان. تعمل فقط مع رسالة يرسلها فنان نشط ومقبول.','IMAP host'=>'مضيف IMAP','e.g. imap.yourhost.com'=>'مثلًا: imap.yourhost.com','IMAP port'=>'منفذ IMAP','Use SSL'=>'استخدام SSL','Skip SSL certificate validation'=>'تجاوز التحقق من شهادة SSL','⚠ Use only as a temporary workaround when your mail server\'s certificate is not yet trusted (e.g. Plesk self-signed cert before Let\'s Encrypt is applied to the mail daemon). Disable this once the mail server presents a valid certificate.'=>'⚠ استخدم هذا فقط كحل مؤقت عندما لا تكون شهادة خادم البريد موثوقة بعد (مثلًا: شهادة Plesk موقعة ذاتيًا قبل تطبيق Let’s Encrypt على خدمة البريد). عطّل هذا الخيار بمجرد أن يعرض خادم البريد شهادة صالحة.','IMAP username'=>'اسم مستخدم IMAP','Login username for the IMAP account — typically the catch-all mailbox address.'=>'اسم مستخدم تسجيل الدخول لحساب IMAP — عادةً عنوان صندوق البريد الشامل.','Submission email password'=>'كلمة مرور بريد الإرسال','Webhook secret'=>'سرّ Webhook','HMAC secret shared with your webhook provider (Mailgun, SendGrid…). Used for both the inbound-mail endpoint (/wp-json/agnosis/v1/email/inbound) and the bounce/complaint events endpoint (/wp-json/agnosis/v1/email/events) — point your provider\'s bounce/spam-complaint webhook at the latter to keep your subscriber and artist addresses clean.'=>'سر HMAC مشترك مع مزوّد الـ webhook لديك (Mailgun، SendGrid…). يُستخدم لكلٍ من نقطة نهاية البريد الوارد (/wp-json/agnosis/v1/email/inbound) ونقطة نهاية أحداث الارتداد/الشكوى (/wp-json/agnosis/v1/email/events) — وجّه webhook الارتداد/الشكوى من مزوّدك إلى الأخيرة للحفاظ على عناوين المشتركين والفنانين نظيفة.','Inbox retention (days)'=>'الاحتفاظ بصندوق الوارد (أيام)','IMAP messages and processed/failed queue rows older than this are permanently deleted by the daily cleanup, whether read or unread. Default: 7 days.'=>'IMAP messages and processed/failed queue rows older than this are permanently deleted by the daily cleanup, whether read or unread. Default: 7 days.','Contact message retention (days)'=>'الاحتفاظ برسائل التواصل (أيام)','Visitor-to-artist contact messages (sent or rejected) older than this are permanently deleted by the daily cleanup. The visitor\'s IP address is cleared independently after 30 days regardless of this setting, once it\'s no longer useful for abuse investigation. Default: 90 days.'=>'تُحذف نهائيًا بواسطة التنظيف اليومي رسائل التواصل من الزائر إلى الفنان (المرسلة أو المرفوضة) الأقدم من هذا. يُزال عنوان IP للزائر بشكل مستقل بعد 30 يومًا بغض النظر عن هذا الإعداد، بمجرد ألا يعود مفيدًا في تحقيقات إساءة الاستخدام. الافتراضي: 90 يومًا.','Per-sender hourly submission limit'=>'الحد الساعي للإرسال لكل مرسل','Maximum submissions accepted from a single artist per hour, across both IMAP and webhook intake. Exceeding this limit silently drops the message (no retry from ESPs). Default: 5.'=>'الحد الأقصى لعدد الإرسالات المقبولة من فنان واحد في الساعة، عبر كلٍ من IMAP والاستقبال عبر webhook. تجاوز هذا الحد يؤدي إلى إسقاط الرسالة بصمت (من دون إعادة محاولة من مزوّدي خدمة البريد). الافتراضي: 5.','Per-artist contact limit'=>'حد التواصل لكل فنان','Maximum messages the same visitor (by email address) can send to a single artist within the window below — applies across every language version of that artist\'s page. Default: 2.'=>'الحد الأقصى لعدد الرسائل التي يمكن للزائر نفسه (بحسب عنوان البريد الإلكتروني) إرسالها إلى فنان واحد ضمن النافذة أدناه — ينطبق عبر كل النسخ اللغوية لصفحة ذلك الفنان. الافتراضي: 2.','Per-artist contact limit window (hours)'=>'نافذة حد التواصل لكل فنان (بالساعات)','Time window, in hours, the per-artist contact limit above applies over. Also controls how long a visitor sees the "already contacted" notice instead of the form after messaging an artist. Default: 1 (one hour).'=>'النافذة الزمنية، بالساعات، التي ينطبق خلالها حد التواصل لكل فنان المذكور أعلاه. كما تتحكم في المدة التي يرى خلالها الزائر إشعار "تم التواصل بالفعل" بدلًا من النموذج بعد مراسلة فنان. الافتراضي: 1 (ساعة واحدة).','Require SPF/DKIM authentication'=>'اشتراط مصادقة SPF/DKIM','When enabled, intake messages must pass SPF or DKIM authentication (via the Authentication-Results header). Prevents spoofed From: addresses. Requires your ESP to include Authentication-Results headers and your domain to have SPF/DKIM records configured. Leave off if you are not sure — rejected legitimate mail is silent. Default: off.'=>'عند التفعيل، يجب أن تجتاز رسائل الإدخال مصادقة SPF أو DKIM (عبر ترويسة Authentication-Results). يمنع انتحال عناوين From:. يتطلب أن يضم مزود خدمة البريد ترويسات Authentication-Results وأن تكون سجلات SPF/DKIM للنطاق مهيأة. اتركه معطّلًا إذا لم تكن متأكدًا — فرفض البريد الشرعي يكون صامتًا. الافتراضي: متوقف.','Description provider'=>'مزود الوصف','Analyzes the artwork image and writes the title, body, tags and alt text. WordPress AI Services delegates to whichever provider the site has configured via the AI Services plugin.'=>'يحلل صورة العمل الفني ويكتب العنوان والنص والوسوم والنص البديل. يفوّض WordPress AI Services إلى المزود الذي يكون الموقع قد أعدّه عبر إضافة AI Services.','OpenAI vision model'=>'نموذج الرؤية من OpenAI','Model used for artwork description when OpenAI is the description provider. Must support vision input.'=>'النموذج المستخدم لوصف العمل الفني عندما يكون OpenAI هو مزود الوصف. يجب أن يدعم إدخال الرؤية البصرية.','Anthropic model'=>'نموذج Anthropic','Model used for artwork description when Anthropic is the description provider. Must support vision input.'=>'النموذج المستخدم لوصف العمل الفني عندما تكون Anthropic هي مزوّد الوصف. يجب أن يدعم إدخال الرؤية.','Vision image max width (px)'=>'الحد الأقصى لعرض صورة الرؤية (بكسل)','Images are downscaled proportionally to this width before being sent to the AI for description — vision token cost scales with resolution, and a description task needs far fewer pixels than the original photo. Applies to artwork photo uploads, rasterised PDF pages, and video poster frames alike. Set to 0 to always send full-resolution images (uses more tokens, no quality difference for typical description tasks). Requires the Imagick PHP extension; images are sent at their original size regardless of this setting when it is unavailable. Default: 800.'=>'يتم تصغير الصور تناسبيًا إلى هذا العرض قبل إرسالها إلى الذكاء الاصطناعي لوصفها — تكلفة رموز الرؤية تتناسب مع الدقة، ومهمة الوصف تحتاج إلى عدد أقل بكثير من البكسلات من الصورة الأصلية. ينطبق ذلك على تحميلات صور الأعمال الفنية، وصفحات PDF المحوَّلة إلى صور نقطية، وإطارات ملصقات الفيديو على حد سواء. اضبطه على 0 لإرسال الصور كاملة الدقة دائمًا (يستخدم رموزًا أكثر، ولا يوجد فرق في الجودة في مهام الوصف المعتادة). يتطلب إضافة Imagick لـ PHP؛ تُرسل الصور بالحجم الأصلي بغض النظر عن هذا الإعداد عندما تكون غير متاحة. الافتراضي: 800.','Enhancement provider'=>'مزود التحسين','Auto (OpenAI if key is set)'=>'تلقائي (OpenAI إذا كان المفتاح مضبوطًا)','Disabled — use original image'=>'معطّل — استخدم الصورة الأصلية','Enhances the artwork image before publishing. Uses OpenAI gpt-image-1. Set to Disabled to skip enhancement and publish the original.'=>'يُحسّن صورة العمل الفني قبل النشر. يستخدم OpenAI gpt-image-1. عيّنها إلى معطّل لتخطي التحسين ونشر الأصل.','OpenAI image model'=>'نموذج صور OpenAI','Model used for image enhancement when OpenAI is the enhancement provider.'=>'النموذج المستخدم لتحسين الصور عندما تكون OpenAI هي مزود التحسين.','Polish biography with AI'=>'تنقيح السيرة الذاتية بالذكاء الاصطناعي','When enabled, biography submissions are passed through the AI to fix spelling and make minor text improvements before saving.'=>'عند التفعيل، تمر طلبات السيرة الذاتية عبر الذكاء الاصطناعي لإصلاح الأخطاء الإملائية وإجراء تحسينات طفيفة على النص قبل الحفظ.','Polish events with AI'=>'تنقيح الفعاليات بالذكاء الاصطناعي','When enabled, event submissions are passed through the AI to fix spelling and make minor text improvements before saving.'=>'عند التفعيل، تمر طلبات الفعاليات عبر الذكاء الاصطناعي لإصلاح الأخطاء الإملائية وإجراء تحسينات طفيفة على النص قبل الحفظ.','Merge biography updates with AI'=>'دمج تحديثات السيرة الذاتية بالذكاء الاصطناعي','When enabled, biography updates are merged with the existing biography using AI — new information is integrated rather than replacing everything. Recommended: artists can send incremental updates ("I just won an award") without resubmitting their full bio. Disable to always replace the biography with the latest submission.'=>'عند التفعيل، تُدمج تحديثات السيرة الذاتية مع السيرة الحالية باستخدام الذكاء الاصطناعي — تُدمج المعلومات الجديدة بدلًا من استبدال كل شيء. موصى به: يمكن للفنانين إرسال تحديثات تدريجية ("لقد فزت للتو بجائزة") دون إعادة إرسال السيرة الكاملة. عطّل هذا الخيار لاستبدال السيرة الذاتية دائمًا بآخر طلب مُرسل.','Rejection threshold (quality score)'=>'عتبة الرفض (درجة الجودة)','Photos scoring at or below this value (1–10) are automatically rejected — the artist receives a friendly email explaining the issue and is invited to resubmit. Score 0 disables automatic rejection. Must be lower than the enhancement threshold. Default: 3.'=>'تُرفض الصور التي تحصل على قيمة مساوية لهذه الدرجة أو أقل منها (1–10) تلقائيًا — ويتلقى الفنان بريدًا إلكترونيًا ودودًا يشرح المشكلة ويدعوه لإعادة الإرسال. تعيّن الدرجة 0 لتعطيل الرفض التلقائي. يجب أن تكون أقل من عتبة التحسين. الافتراضي: 3.','Enhancement threshold (quality score)'=>'عتبة التحسين (درجة الجودة)','Photos scoring below this value (1–10) are automatically enhanced. Score 10 = perfect photograph, 1 = technically unusable. Default: 7 — only visibly problematic photos are processed. Set to 1 to disable automatic enhancement entirely.'=>'تُحسَّن الصور التي تحصل على درجة أقل من هذه القيمة (1–10) تلقائيًا. الدرجة 10 = صورة مثالية، 1 = غير صالحة تقنيًا للاستخدام. الافتراضي: 7 — تُعالج فقط الصور التي بها مشكلات ظاهرة. اضبطها على 1 لتعطيل التحسين التلقائي بالكامل.','OpenAI API key'=>'مفتاح واجهة برمجة تطبيقات OpenAI','Required when OpenAI is the description or enhancement provider.'=>'مطلوب عندما تكون OpenAI هي مزود الوصف أو التحسين.','Anthropic API key'=>'مفتاح واجهة برمجة تطبيقات Anthropic','Required when Anthropic is the description provider.'=>'مطلوب عندما تكون Anthropic هي مزود الوصف.','Artwork display width (px)'=>'عرض عرض العمل الفني (بكسل)','Width of the agnosis-artwork image size used in post content and lightbox. Height scales proportionally. Default: 1920. Existing images need to be regenerated after changing this value.'=>'عرض صورة agnosis-artwork المستخدم في محتوى المنشور وفي العرض المكبّر. يتناسب الارتفاع تلقائيًا. الافتراضي: 1920. يجب إعادة إنشاء الصور الحالية بعد تغيير هذه القيمة.','Thumbnail size (px)'=>'حجم الصورة المصغرة (بكسل)','Side length of the square agnosis-thumb size used in submission cards and dashboard. Default: 512. Existing images need to be regenerated after changing this value.'=>'طول ضلع الحجم المربع agnosis-thumb المستخدم في بطاقات الإرسال ولوحة التحكم. الافتراضي: 512. يجب إعادة إنشاء الصور الحالية بعد تغيير هذه القيمة.','Email image width (px)'=>'عرض صورة البريد الإلكتروني (بكسل)','Width of the agnosis-email size used in artist notification emails. Height scales proportionally — no cropping. Default: 420. Existing images need to be regenerated after changing this value.'=>'عرض حجم agnosis-email المستخدم في رسائل إشعار الفنانين عبر البريد الإلكتروني. يتناسب الارتفاع تلقائيًا — دون قص. الافتراضي: 420. يجب إعادة إنشاء الصور الحالية بعد تغيير هذه القيمة.','Gallery overview — items per page'=>'نظرة عامة على المعرض — العناصر في كل صفحة','How many artwork cards the gallery overview shows per page. Pool is built proportionally across all artists; featured artworks are preferred. Default: 12.'=>'عدد بطاقات الأعمال الفنية التي تعرضها نظرة عامة على المعرض في كل صفحة. يُبنى التجميع بنسبة متناسبة عبر جميع الفنانين؛ وتُفضَّل الأعمال الفنية المميّزة. الافتراضي: 12.','Review link expiry (days)'=>'انتهاء صلاحية رابط المراجعة (أيام)','How long the Approve & Publish / Discard links in a submission review email stay valid before an artist has to log in to manage the item instead. Applies uniformly to artwork, biography, and event drafts. Default: 7.'=>'المدة التي تبقى خلالها روابط الموافقة والنشر / الرفض في رسالة مراجعة الإرسال صالحة قبل أن يضطر الفنان إلى تسجيل الدخول لإدارة العنصر بدلًا من ذلك. ينطبق ذلك بالتساوي على مسودات الأعمال الفنية والسير الذاتية والفعاليات. الافتراضي: 7.','System prompt'=>'موجه النظام','Sent to the AI as the system instruction. Use {tag_count} and {excerpt_words} as tokens — they are replaced with the values below.'=>'يُرسل إلى الذكاء الاصطناعي كتوجيه للنظام. استخدم {tag_count} و {excerpt_words} كرموز مميزة — وسيتم استبدالها بالقيم أدناه.','Artist prompt template'=>'قالب موجه الفنان','User message sent alongside the artwork image. Use {artist_prompt} where the artist\'s own description should appear.'=>'رسالة المستخدم المرسلة مع صورة العمل الفني. استخدم {artist_prompt} حيث يجب أن يظهر وصف الفنان نفسه.','Enhancement instructions'=>'تعليمات التحسين','Instructions passed to the image enhancement provider. The AI-generated artwork description is appended automatically as context.'=>'تعليمات تُمرَّر إلى مزود تحسين الصور. يُضاف الوصف المُنشأ بواسطة الذكاء الاصطناعي تلقائيًا كسياق.','Number of tags'=>'عدد الوسوم','How many tags the AI should generate per artwork. Referenced as {tag_count} in the system prompt.'=>'عدد الوسوم التي يجب أن ينشئها الذكاء الاصطناعي لكل عمل فني. يُشار إليه بـ {tag_count} في موجه النظام.','Excerpt word limit'=>'حد كلمات المقتطف','Maximum words for the one-sentence excerpt. Referenced as {excerpt_words} in the system prompt.'=>'الحد الأقصى لعدد الكلمات في المقتطف ذي الجملة الواحدة. يُشار إليه بـ {excerpt_words} في موجه النظام.','Trust all admitted artists (skip link review entirely)'=>'الثقة بجميع الفنانين المقبولين (تخطي مراجعة الروابط بالكامل)','Every artist here was already vouched in by the community — if that trust is enough for you, turn this on to embed any link an artist submits, immediately, with no allowlist check and no AI review at all (the settings below are skipped entirely while this is on). Off by default. Only enable this if you are comfortable that a bad actor who made it through admission could embed a link to anything.'=>'كل فنان هنا كان قد حظي بالفعل بتزكية من المجتمع — إذا كانت هذه الثقة كافية بالنسبة لك، ففعّل هذا الخيار لدمج أي رابط يرسله الفنان فورًا، دون أي تحقق من القائمة المسموح بها ودون أي مراجعة بالذكاء الاصطناعي على الإطلاق (تُتجاوز الإعدادات أدناه بالكامل أثناء التفعيل). يكون معطّلًا افتراضيًا. فعّله فقط إذا كنت مرتاحًا لاحتمال أن يتمكن سيئ النية الذي اجتاز القبول من تضمين رابط إلى أي شيء.','Trusted embed platforms'=>'منصات التضمين الموثوقة','One hostname per line. A submitted link becomes a rich embed immediately if it matches one of these (or a subdomain of one) — no AI review needed, no network request made to the link itself.'=>'اسم مضيف واحد في كل سطر. يصبح الرابط المُرسَل تضمينًا غنيًا فورًا إذا طابق أحد هذه المضيفات (أو نطاقًا فرعيًا لأحدها) — دون الحاجة إلى مراجعة بالذكاء الاصطناعي، ودون إرسال أي طلب شبكة إلى الرابط نفسه.','Let artists submit other links too (AI-reviewed)'=>'السماح للفنانين بإرسال روابط أخرى أيضًا (تخضع لمراجعة الذكاء الاصطناعي)','When enabled, a link to a site not on the trusted list above is not simply discarded: the destination page is fetched and reviewed by your configured AI provider (Settings → AI Providers) against the categories below before deciding whether to embed it. If the AI cannot be reached, the request times out, or the page cannot be safely fetched, the link is not embedded — it fails safe. When disabled (the default), only the trusted platforms above are ever embedded.'=>'عند التفعيل، فإن الرابط إلى موقع غير موجود في القائمة الموثوقة أعلاه لا يُهمل ببساطة: تُجلب الصفحة المقصودة وتُراجع بواسطة مزود الذكاء الاصطناعي الذي ضبطته (الإعدادات ← مزوّدو الذكاء الاصطناعي) وفق الفئات أدناه قبل اتخاذ قرار تضمينها. إذا تعذر الوصول إلى الذكاء الاصطناعي، أو انتهت المهلة، أو تعذّر جلب الصفحة بأمان، فلن يُضمَّن الرابط — بل يفشل بأمان. عند التعطيل (الافتراضي)، لا تُضمَّن إلا المنصات الموثوقة أعلاه.','Block pornographic / sexually explicit content'=>'حظر المحتوى الإباحي / الصريح جنسيًا','Only takes effect when AI review (above) is enabled.'=>'لا يسري إلا عند تفعيل مراجعة الذكاء الاصطناعي (أعلاه).','Block primarily commercial / promotional sites'=>'حظر المواقع التجارية / الترويجية بالأساس','Online stores, advertising, marketing landing pages. Off by default — an artist linking to a shop selling their own prints is common and not inherently unwanted. Only takes effect when AI review (above) is enabled.'=>'المتاجر الإلكترونية، والإعلانات، وصفحات الهبوط التسويقية. يكون معطّلًا افتراضيًا — فمن الشائع أن يربط الفنان متجرًا يبيع مطبوعاته الخاصة، وهذا ليس غير مرغوب فيه بطبيعته. لا يسري إلا عند تفعيل مراجعة الذكاء الاصطناعي (أعلاه).','Block gambling / betting sites'=>'حظر مواقع المقامرة / الرهان','Additional disallowed categories'=>'فئات إضافية غير مسموح بها','Optional — describe any other kind of content the AI should reject, in plain language (e.g. "hate speech or violent extremist content", "phishing or scam pages"). Only takes effect when AI review (above) is enabled.'=>'اختياري — صف أي نوع آخر من المحتوى ينبغي على الذكاء الاصطناعي رفضه، بلغة واضحة (مثلًا: "خطاب الكراهية أو المحتوى المتطرف العنيف"، "صفحات التصيد أو الاحتيال"). لا يسري إلا عند تفعيل مراجعة الذكاء الاصطناعي (أعلاه).','Node label'=>'تسمية العقدة','How this node introduces itself to the network.'=>'كيف تُعرّف هذه العقدة نفسها للشبكة.','Enable ActivityPub federation'=>'تمكين اتحاد ActivityPub','Broadcast new artworks to Mastodon, Pixelfed and the Fediverse.'=>'بثّ الأعمال الفنية الجديدة إلى Mastodon وPixelfed وFediverse.','Node public key'=>'المفتاح العام للعقدة','Auto-generated RSA public key for this node. Share this with peer nodes.'=>'مفتاح RSA عام مُولَّد تلقائيًا لهذه العقدة. شاركه مع العقد النظيرة.','Sender name'=>'اسم المرسل','Name shown as the sender of admission, vote, welcome, departure, and other workflow emails. Leave blank to use the site name.'=>'الاسم الظاهر كمرسل لرسائل القبول، والتصويت، والترحيب، والمغادرة، ورسائل سير العمل الأخرى. اتركه فارغًا لاستخدام اسم الموقع.','Sender email address'=>'عنوان بريد المرسل الإلكتروني','Dedicated From: address for admission, vote, welcome, departure, invitation, and submission-review emails — e.g. hello@agnosis.art. Deliberately separate from the Settings → Newsletter sender: these are one-off actions (a vote link, a review link), not digest mail. Leave blank to use the admin email. Must be a valid, deliverable address on your domain (SPF/DKIM configured) or messages may be marked as spam.'=>'عنوان From: مخصص لرسائل القبول، والتصويت، والترحيب، والمغادرة، والدعوة، ومراجعة الإرسال — مثل hello@agnosis.art. منفصل عمدًا عن إعدادات → مرسل النشرة الإخبارية: فهذه إجراءات لمرة واحدة (رابط تصويت، رابط مراجعة)، وليست رسائل ملخّصة. اتركه فارغًا لاستخدام بريد المشرف الإلكتروني. يجب أن يكون عنوانًا صالحًا وقابلاً للتسليم على نطاقك (مع إعداد SPF/DKIM) وإلا فقد تُعلَّم الرسائل كرسائل مزعجة.','Self-removal (goodbye) requests per sender per day'=>'طلبات الإزالة الذاتية (المغادرة) لكل مرسل في اليوم','Maximum number of self-removal ("goodbye") confirmation emails a single sender address can trigger per day. A genuine self-removal only ever needs to be requested once — this caps how many confirmation emails a spoofed or repeated From can be used to spam a real artist with. Default: 3.'=>'الحد الأقصى لعدد رسائل تأكيد الإزالة الذاتية («المغادرة») التي يمكن أن يطلقها عنوان مرسل واحد في اليوم. الإزالة الذاتية الحقيقية لا تحتاج إلا إلى طلب واحد — وهذا يحد من عدد رسائل التأكيد التي يمكن أن يُستخدم فيها From مزيف أو متكرر لإزعاج فنان حقيقي. القيمة الافتراضية: 3.','Community broadcasts per artist per day'=>'بثوث المجتمع لكل فنان في اليوم','Maximum number of messages a single artist can send to the Community announcement address (Settings → Email) per day. Prevents one member from flooding every other member\'s inbox. Default: 3.'=>'الحد الأقصى لعدد الرسائل التي يمكن لفنان واحد إرسالها إلى عنوان إعلانات المجتمع (الإعدادات → البريد الإلكتروني) في اليوم. يمنع عضوًا واحدًا من إغراق صندوق وارد كل الأعضاء الآخرين. القيمة الافتراضية: 3.','Community broadcast max length (characters)'=>'الحد الأقصى لطول بث المجتمع (بالأحرف)','Longer messages to the Community announcement address are bounced back to the sender instead of being broadcast — the sender is told to shorten it and resend. Measured in characters, not words, so it applies fairly across languages that don\'t use spaces between words (Chinese, Japanese, Thai, etc.). Every recipient\'s copy is translated individually, so this also caps how much a single message can cost in AI translation calls. Default: 2000. Hard maximum: 20000, regardless of this setting.'=>'الرسائل الأطول المرسلة إلى عنوان إعلانات المجتمع تُعاد إلى المرسل بدلًا من بثّها — ويُطلب من المرسل تقصيرها وإعادة إرسالها. يُقاس بعدد الأحرف لا الكلمات، لذا فهو ينطبق بعدالة على اللغات التي لا تستخدم المسافات بين الكلمات (الصينية، اليابانية، التايلاندية، إلخ). تُترجم نسخة كل مستلم على حدة، لذا فإن هذا يحد أيضًا من مقدار ما يمكن أن تكلفه رسالة واحدة من استدعاءات ترجمة الذكاء الاصطناعي. القيمة الافتراضية: 2000. الحد الأقصى الصارم: 20000، بغض النظر عن هذا الإعداد.','Admission vote threshold (%)'=>'نسبة عتبة القبول (%)','Percentage of active artists that must vote yes for admission. Combined with the minimum floor below.'=>'النسبة المئوية من الفنانين النشطين الذين يجب أن يصوّتوا بنعم للقبول. تُستخدم مع الحد الأدنى أدناه.','Admission minimum votes'=>'الحد الأدنى لعدد أصوات القبول','Absolute minimum positive votes required regardless of the percentage above.'=>'الحد الأدنى المطلق للأصوات الإيجابية المطلوبة بغض النظر عن النسبة أعلاه.','Voting window (days)'=>'نافذة التصويت (بالأيام)','Days an application stays open. If the threshold is not reached within this window the application is rejected.'=>'عدد الأيام التي يبقى فيها الطلب مفتوحًا. إذا لم تُبلَغ العتبة خلال هذه النافذة، يُرفض الطلب.','Resolved application retention (days)'=>'مدة الاحتفاظ بالطلبات المحسومة (بالأيام)','A rejected, withdrawn, or left application\'s email, name, biography, statement, and portfolio link are anonymized by the daily cleanup after this many days — the application record itself (status and dates) is kept for admission history. A banned artist\'s biography/statement/portfolio are anonymized on the same schedule, but their email is deliberately kept so the ban stays enforceable. Default: 180 days.'=>'يتم إخفاء هوية البريد الإلكتروني والاسم والسيرة الذاتية والبيان ورابط المعرض لطلب مرفوض أو مسحوب أو متروك بواسطة التنظيف اليومي بعد هذا العدد من الأيام — بينما يُحتفَظ بسجل الطلب نفسه (الحالة والتواريخ) لتاريخ القبول. أما سيرة الفنان/بيانه/رابطه فيتم إخفاء هويتها وفق الجدول نفسه، لكن يُحتفَظ ببريده الإلكتروني عمدًا لكي يظل الحظر قابلًا للتنفيذ. القيمة الافتراضية: 180 يومًا.','After applying, send artists to'=>'بعد التقديم، إرسال الفنانين إلى','Optional — pick a page explaining the vouching process and what happens next. When the application is submitted successfully, the artist is redirected there instead of just seeing an inline confirmation message. Leave as "None" to keep the inline message only.'=>'اختياري — اختر صفحة تشرح عملية التزكية وما الذي يحدث بعد ذلك. عند إرسال الطلب بنجاح، يُعاد توجيه الفنان إليها بدلًا من رؤية رسالة تأكيد مضمّنة فقط. اتركه على «None» للاكتفاء برسالة التأكيد المضمّنة.','Community size cap'=>'الحد الأقصى لحجم المجتمع','Maximum number of admitted artists. When full, new applications join a waitlist instead of being rejected, and a freed slot admits the next in line. Set to 0 for no cap. The community can also vote to change this.'=>'الحد الأقصى لعدد الفنانين المقبولين. عند الامتلاء، تنضم الطلبات الجديدة إلى قائمة انتظار بدلًا من رفضها، ويُقبِل الموضع الشاغر التالي في القائمة. عيّنها إلى 0 لعدم وجود حد. ويمكن للمجتمع أيضًا التصويت لتغيير ذلك.','Cap-change co-signers required'=>'عدد المشاركين المطلوبين لتغيير الحد الأقصى','How many artists must co-sign a proposal to change the community size cap before it opens as a full community vote.'=>'كم عدد الفنانين الذين يجب أن يشاركوا في توقيع اقتراح لتغيير الحد الأقصى لحجم المجتمع قبل أن يُفتح كتصويت مجتمعي كامل.','Cap-change vote window (days)'=>'نافذة التصويت لتغيير الحد الأقصى (بالأيام)','Days a community cap-change vote stays open. A strict majority of active artists voting yes adopts the new cap.'=>'عدد الأيام التي يبقى فيها تصويت تغيير حد المجتمع مفتوحًا. اعتماد الحد الأقصى الجديد يتطلب أغلبية بسيطة من الفنانين النشطين الذين يصوّتون بنعم.','Removal nominations required'=>'عدد الترشيحات المطلوبة للإزالة','Number of artist nominations needed before a community removal vote opens. Admins can bypass this threshold.'=>'عدد ترشيحات الفنانين المطلوبة قبل فتح تصويت إزالة مجتمعي. يمكن للمشرفين تجاوز هذه العتبة.','Removal vote window (days)'=>'نافذة التصويت للإزالة (بالأيام)','Days a community removal vote stays open. A majority (>50%) of active artists must vote yes for removal to proceed.'=>'عدد الأيام التي يبقى فيها تصويت إزالة مجتمعي مفتوحًا. يجب أن تصوّت أغلبية (>50%) من الفنانين النشطين بنعم لتمضي الإزالة.','Invitation intro'=>'مقدمة الدعوة','Agnosis is a small, self-hosted home for artists who\'d rather make work than manage a platform. There\'s no algorithm deciding who sees your art, no portfolio site to maintain, and no account to configure — just your work, published and translated automatically for a global audience.

Being part of the community is simple: Fellow artists vouch for new applicants, and everyone keeps full ownership of what they publish; you can leave at any time and take your work with you.

Once admitted, you submit new work by sending it as an email — no dashboard, no forms and you can update, promote or remove your artwork as well sending an email. You can find more information visiting the agnosis.art website.'=>'Agnosis هو موطن صغير ومستضاف ذاتيًا للفنانين الذين يفضّلون صنع الأعمال بدلًا من إدارة منصة. لا توجد خوارزمية تقرر من يرى فنك، ولا موقع معرض تحتاج إلى صيانته، ولا حساب تحتاج إلى ضبطه — فقط أعمالك، منشورة ومترجمة تلقائيًا لجمهور عالمي.

الانضمام إلى المجتمع بسيط: يزكّي فنانون آخرون المتقدمين الجدد، ويحافظ الجميع على الملكية الكاملة لما ينشرونه؛ يمكنك المغادرة في أي وقت وأخذ أعمالك معك.

بعد القبول، ترسل أعمالك الجديدة عبر البريد الإلكتروني — بلا لوحة تحكم، بلا نماذج، ويمكنك أيضًا تحديث أعمالك الفنية أو الترويج لها أو إزالتها بإرسال بريد إلكتروني. يمكنك العثور على مزيد من المعلومات بزيارة موقع agnosis.art.','Shown near the top of the "Send Invitation" email below (an "Apply to join" link and site name follow automatically — no need to add either here). Two or three short paragraphs is plenty. Standing copy, not cleared after use like the newsletter intros above — translated automatically when an invitation is sent in a language other than the site\'s own.'=>'يُعرض قرب أعلى رسالة «إرسال دعوة» أدناه (سيأتي تلقائيًا رابط «التقديم للانضمام» واسم الموقع — لا حاجة لإضافة أيٍّ منهما هنا). تكفي فقرتان أو ثلاث قصيرات. نص ثابت، لا يُمسح بعد الاستخدام مثل مقدمات النشرة الإخبارية أعلاه — ويُترجم تلقائيًا عند إرسال الدعوة بلغة مختلفة عن لغة الموقع.','Transaction fee (%)'=>'رسوم المعاملة (%)','Percentage retained by this node on donations and art sales. Artists pay nothing up front.'=>'النسبة التي يحتفظ بها هذا العقد من التبرعات ومبيعات الأعمال الفنية. لا يدفع الفنانون شيئًا مقدمًا.','Name shown as the sender of digest emails. Leave blank to use the site name.'=>'الاسم الظاهر كمرسل لرسائل الملخّص. اتركه فارغًا لاستخدام اسم الموقع.','Dedicated From: address for both newsletters, e.g. newsletter@agnosis.art — keeps digest mail separate from the site\'s admin email for deliverability and so artists can filter it. Leave blank to use the admin email. Must be a valid, deliverable address on your domain (SPF/DKIM configured) or messages may be marked as spam.'=>'عنوان البريد "من:" المخصص لكلا النشرتين، مثل newsletter@agnosis.art — يفصل بريد الملخص عن البريد الإداري للموقع لتحسين قابلية التسليم، بحيث يمكن للفنانين تصفيته. اتركه فارغًا لاستخدام البريد الإداري. يجب أن يكون عنوانًا صالحًا وقابلًا للتسليم على نطاقك (تم إعداد SPF/DKIM) وإلا قد تُعلَّم الرسائل كبريد عشوائي.','Auto-draft newsletter intros'=>'إنشاء مقدمات النشرة تلقائيًا كمسودة','When enabled, Agnosis drafts an intro via AI ahead of each issue (see the lead time below), saves it to that newsletter\'s intro field, and emails you to review it — unless you\'ve already written one for that cycle. Disable to leave both intro fields exactly as you left them, always.'=>'عند التفعيل، تقوم Agnosis بصياغة مقدمة عبر الذكاء الاصطناعي قبل كل عدد (انظر مهلة الإعداد أدناه)، وتحفظها في حقل المقدمة الخاص بتلك النشرة، وترسل إليك بريدًا لمراجعتها — إلا إذا كنت قد كتبت مقدمة بالفعل لتلك الدورة. عطِّل هذا الخيار لترك حقلي المقدمة كما تركتهما تمامًا، دائمًا.','Draft intro this many hours ahead'=>'أنشئ المسودة قبل هذا العدد من الساعات','How long before an issue is due Agnosis proposes an AI-drafted intro. Only takes effect when auto-drafting (above) is enabled. Default: 24.'=>'المدة الزمنية قبل استحقاق العدد التي تقترح فيها Agnosis مقدمة مُصاغة بالذكاء الاصطناعي. لا يسري إلا عند تفعيل إنشاء المسودات تلقائيًا (أعلاه). القيمة الافتراضية: 24.','Artist newsletter'=>'النشرة الإخبارية للفنانين','Admitted artists are auto-enrolled (they can unsubscribe from any issue with one click). Community digest: recent activity, new members, open votes.'=>'يُسجَّل الفنانون المقبولون تلقائيًا في الاشتراك (ويمكنهم إلغاء الاشتراك من أي عدد بنقرة واحدة). ملخص المجتمع: النشاط الأخير، الأعضاء الجدد، التصويتات المفتوحة.','Artist newsletter frequency (days)'=>'تكرار النشرة الإخبارية للفنانين (بالأيام)','Default 30 ≈ monthly. A new issue is prepared once this many days have passed since the last one was sent.'=>'القيمة الافتراضية 30 ≈ شهريًا. يتم إعداد عدد جديد بعد مرور هذا العدد من الأيام منذ إرسال العدد السابق.','Artist newsletter intro'=>'مقدمة النشرة الإخبارية للفنانين','Optional note prepended to the next artist issue only — cleared automatically once that issue is queued. Leave blank to send the auto-digest with no intro. If left blank, Agnosis drafts one automatically from what\'s new about a day before the issue sends, and emails you to review it first — write your own here any time to skip that.'=>'ملاحظة اختيارية تُضاف قبل إصدار الفنان التالي فقط — تُمسح تلقائيًا بمجرد وضع هذا الإصدار في قائمة الانتظار. اتركها فارغة لإرسال الملخص التلقائي من دون مقدمة. إذا تُركت فارغة، فإن Agnosis يصوغ واحدة تلقائيًا مما هو جديد قبل نحو يوم من إرسال الإصدار، ويرسل إليك بريدًا لمراجعتها أولًا — اكتبها بنفسك هنا في أي وقت لتجاوز ذلك.','Public newsletter'=>'النشرة الإخبارية العامة','Visitors subscribe via the agnosis/newsletter-signup block (double opt-in). Digest: new artwork and events published since the last issue.'=>'يشترك الزوار عبر كتلة agnosis/newsletter-signup (تأكيد مزدوج). الملخص: الأعمال الفنية والفعاليات الجديدة المنشورة منذ الإصدار الأخير.','Public newsletter frequency (days)'=>'تكرار النشرة الإخبارية العامة (بالأيام)','Default 30 ≈ monthly.'=>'الافتراضي 30 ≈ شهريًا.','Public newsletter intro'=>'مقدمة النشرة الإخبارية العامة','Optional note prepended to the next public issue only — cleared automatically once that issue is queued. If left blank, Agnosis drafts one automatically from what\'s new about a day before the issue sends, and emails you to review it first — write your own here any time to skip that.'=>'ملاحظة اختيارية تُضاف قبل الإصدار العام التالي فقط — تُمسح تلقائيًا بمجرد وضع هذا الإصدار في قائمة الانتظار. إذا تُركت فارغة، فإن Agnosis يصوغ واحدة تلقائيًا مما هو جديد قبل نحو يوم من إرسال الإصدار، ويرسل إليك بريدًا لمراجعتها أولًا — اكتبها بنفسك هنا في أي وقت لتجاوز ذلك.','Send batch size'=>'حجم دفعة الإرسال','Recipients emailed per 5-minute cron tick. Lower this if your host throttles outbound mail; raise it for faster delivery on hosts with generous limits.'=>'عدد المستلمين الذين يُرسل إليهم البريد في كل نبضة cron مدتها 5 دقائق. خفّض هذه القيمة إذا كان مضيفك يحدّ من البريد الصادر؛ وارفعها لتسليم أسرع على المضيفين ذوي الحدود السخية.','Self-hosting comfort threshold'=>'عتبة الراحة للاستضافة الذاتية','Advisory only — self-hosted sending keeps working above this count. Once confirmed public subscribers pass it, this page shows a reminder to consider an email service provider (e.g. Brevo\'s free tier) instead.'=>'إرشادي فقط — يظل الإرسال المستضاف ذاتيًا يعمل فوق هذا العدد. بمجرد تأكيد أن عدد المشتركين العامين قد تجاوزه، تعرض هذه الصفحة تذكيرًا بالنظر في استخدام مزود خدمة بريد إلكتروني (مثل الخطة المجانية من Brevo) بدلًا من ذلك.','Sends a minimal ping ("Reply with the word: ping") using the configured API key.'=>'يرسل نبضة تحقق بسيطة ("ردّ بالكلمة: ping") باستخدام مفتاح API المُكوَّن.','Sends a minimal ping using the configured API key.'=>'يرسل نبضة تحقق بسيطة باستخدام مفتاح API المُكوَّن.','WordPress AI Client'=>'عميل الذكاء الاصطناعي لـ WordPress','Checks that wp_ai_client_prompt() is available (WordPress 7.0+) and a text-generation model is configured.'=>'يتحقق من توفر wp_ai_client_prompt() (WordPress 7.0+) ومن أن نموذج توليد نصوص مُكوَّن.','Test AI Providers'=>'اختبار مزوّدي الذكاء الاصطناعي','Test %s'=>'اختبار %s','Bot Protection'=>'الحماية من الروبوتات','Turnstile is configured.'=>'تم إعداد Turnstile.','The Join application form and the Newsletter Subscribe form both require human verification before they accept a submission.'=>'يتطلب كلٌّ من نموذج طلب الانضمام ونموذج الاشتراك في النشرة الإخبارية التحقق البشري قبل قبول أي إرسال.','Turnstile is not configured.'=>'لم يتم إعداد Turnstile.','Your Join application form is public — anyone can submit an application, and a submitted (and confirmed) application still emails every admitted artist and admin. Right now the only thing standing between that form and an automated bot is a fixed 5-submissions-per-minute-per-IP limit, which a distributed bot can work around entirely. Add a Cloudflare Turnstile site key and secret key above to require human verification on both the Join form and the Newsletter Subscribe form.'=>'نموذج طلب الانضمام لديك عام — يمكن لأي شخص إرسال طلب، والطلب المُرسل (والمؤكَّد) سيُرسل أيضًا بريدًا إلى كل فنان ومدير مُعتمد. في الوقت الحالي، الشيء الوحيد الذي يفصل بين هذا النموذج وبوت آلي هو حد ثابت قدره 5 إرساليات لكل دقيقة لكل عنوان IP، ويمكن لبوت موزع التحايل عليه بالكامل. أضف مفتاح موقع ومفتاحًا سريًا لـ Cloudflare Turnstile أعلاه لفرض التحقق البشري على كلٍّ من نموذج الانضمام ونموذج الاشتراك في النشرة الإخبارية.','OpenAI'=>'OpenAI','Anthropic'=>'Anthropic','AI Processing & Privacy Policy'=>'سياسة معالجة الذكاء الاصطناعي والخصوصية','A Privacy Policy page is set.'=>'تم تعيين صفحة سياسة خصوصية.','Suggested wording covering %s and public federation was added to it automatically — review it under Settings → Privacy → "Guide" before publishing, and check with your provider(s) about their own data processing agreement (DPA) for your compliance obligations.'=>'تمت إضافة صياغة مقترحة تغطي %s والتوحيد العام تلقائيًا — راجعها ضمن الإعدادات ← الخصوصية ← "الدليل" قبل النشر، وتحقق مع مزود(ي) الخدمة من اتفاقية معالجة البيانات الخاصة بهم (DPA) بشأن التزامات الامتثال لديك.','No Privacy Policy page is set.'=>'لم يتم تعيين صفحة سياسة خصوصية.','Submitted artwork, text, and visitor contact messages are sent to %s for processing. Create or choose a page under Settings → Privacy — this plugin has already prepared suggested wording you\'ll find there under "Guide". You may also want to review that provider\'s data processing agreement (DPA) for your own compliance obligations.'=>'يتم إرسال الأعمال الفنية والنصوص ورسائل التواصل من الزوار التي تم تقديمها إلى %s لمعالجتها. أنشئ صفحة أو اختر واحدة ضمن الإعدادات ← الخصوصية — فقد أعدّت هذه الإضافة بالفعل صياغة مقترحة ستجدها هناك تحت "الدليل". وقد ترغب أيضًا في مراجعة اتفاقية معالجة البيانات (DPA) الخاصة بهذا المزود بشأن التزامات الامتثال لديك.','Go to Settings → Privacy'=>'انتقل إلى الإعدادات ← الخصوصية','Debug Files'=>'ملفات التصحيح','Currently'=>'حاليًا','Enabled'=>'مفعّل','Disabled'=>'معطّل','Forced ON by the AGNOSIS_DEBUG constant in wp-config.php — the checkbox above has no effect until that line is removed.'=>'مفروض التشغيل بواسطة الثابت AGNOSIS_DEBUG في wp-config.php — لن يكون لمربع الاختيار أعلاه أي تأثير حتى تتم إزالة ذلك السطر.','Forced OFF by the AGNOSIS_DEBUG constant in wp-config.php — the checkbox above has no effect until that line is removed.'=>'مفروض الإيقاف بواسطة الثابت AGNOSIS_DEBUG في wp-config.php — لن يكون لمربع الاختيار أعلاه أي تأثير حتى تتم إزالة ذلك السطر.','Directory'=>'الدليل','Filter with agnosis_debug_dir to redirect debug output elsewhere.'=>'يمكن التصفية باستخدام agnosis_debug_dir لإعادة توجيه مخرجات التصحيح إلى مكان آخر.','.txt file(s) in the directory'=>'ملف(ات) .txt في الدليل','Delete all .txt files in the debug directory? The directory itself stays in place so future debug writes still land cleanly.'=>'حذف جميع ملفات .txt في دليل التصحيح؟ سيبقى الدليل نفسه في مكانه حتى تظل عمليات كتابة التصحيح المستقبلية تتم بشكل سليم.','Clear Debug Files'=>'مسح ملفات التصحيح','Term Translation Cache'=>'ذاكرة التخزين المؤقت لترجمات المصطلحات','Cached translations'=>'الترجمات المخزنة مؤقتًا','AI-translated tag/medium term names, cached so the same term always gets the same translated label instead of a fresh AI phrasing per post. Renaming a term already clears its own cached entry automatically; use the button below only if a cached translation itself is wrong.'=>'أسماء المصطلحات الخاصة بالوسوم/الوسائط المترجمة بالذكاء الاصطناعي، والمخزنة مؤقتًا بحيث يحصل المصطلح نفسه دائمًا على نفس التسمية المترجمة بدلًا من صياغة جديدة من الذكاء الاصطناعي لكل منشور. إعادة تسمية المصطلح تمسح بالفعل إدخال ذاكرته المؤقتة تلقائيًا؛ استخدم الزر أدناه فقط إذا كانت ترجمة مخزنة نفسها خاطئة.','Clear every cached term translation? Nothing is deleted from your site — terms will simply be re-translated by AI the next time they\'re needed.'=>'مسح كل ترجمات المصطلحات المخزنة مؤقتًا؟ لن يُحذف أي شيء من موقعك — ستُعاد ترجمة المصطلحات بواسطة الذكاء الاصطناعي في المرة التالية التي تحتاج فيها إليها.','Clear Term Translation Cache'=>'مسح ذاكرة التخزين المؤقت لترجمات المصطلحات','Pipeline Logs'=>'سجلات خط الأنابيب','Clear all log entries?'=>'مسح جميع إدخالات السجل؟','Clear All'=>'مسح الكل','%d entries total. Logs are pruned automatically according to the Inbox retention setting.'=>'%d إدخالًا إجمالًا. تُنقّى السجلات تلقائيًا وفقًا لإعداد الاحتفاظ بصندوق الوارد.','No log entries yet.'=>'لا توجد سجلات في السجل بعد.','Time'=>'الوقت','Level'=>'المستوى','Context'=>'السياق','Inbox Tools'=>'أدوات صندوق الوارد','Test connection'=>'اختبار الاتصال','Test IMAP Connection'=>'اختبار اتصال IMAP','Connects to the configured mailbox and reports the total and unseen message count.'=>'يتصل بصندوق البريد المُهيأ ويعرض العدد الإجمالي للرسائل والرسائل غير المقروءة.','Poll inbox now'=>'استرجاع صندوق الوارد الآن','Poll Inbox Now'=>'استرجاع صندوق الوارد الآن','Fetches unseen messages immediately without waiting for WP-Cron. Then click "Process Pending Queue" to run the AI pipeline.'=>'يجلب الرسائل غير المقروءة فورًا دون انتظار WP-Cron. ثم انقر "معالجة قائمة الانتظار المعلقة" لتشغيل خط أنابيب الذكاء الاصطناعي.','Process queue'=>'معالجة قائمة الانتظار','Process Pending Queue'=>'معالجة قائمة الانتظار المعلقة','Immediately runs the AI pipeline on all pending queue items without waiting for WP-Cron. Use this to test the end-to-end flow after a poll.'=>'يشغّل خط أنابيب الذكاء الاصطناعي فورًا على جميع عناصر قائمة الانتظار المعلقة دون انتظار WP-Cron. استخدم هذا لاختبار التدفق من البداية إلى النهاية بعد الاسترجاع.','Force reprocess'=>'فرض إعادة المعالجة','Force Reprocess Inbox'=>'فرض إعادة معالجة صندوق الوارد','Resets failed/stuck/orphaned queue rows back to pending, then immediately polls for unprocessed messages. Then click "Process Pending Queue" to run the AI pipeline. Already-published artworks with valid posts are never re-processed.'=>'يعيد تعيين صفوف قائمة الانتظار الفاشلة/العالقة/اليتيمة إلى حالة "معلقة"، ثم يسترجع الرسائل غير المعالجة فورًا. ثم انقر "معالجة قائمة الانتظار المعلقة" لتشغيل خط أنابيب الذكاء الاصطناعي. الأعمال الفنية المنشورة بالفعل ذات المنشورات الصالحة لا تتم إعادة معالجتها أبدًا.','Deliverability'=>'قابلية التسليم','A diagnostic check only — nothing here changes how mail is sent. On ordinary hosting (PHP mail(), no SMTP plugin), mail sent from an address that doesn\'t match your site\'s own domain, or from a domain with no SPF/DMARC record at all, is increasingly likely to land in spam or be rejected outright by large mailbox providers. If any row below looks wrong, the most reliable fix is installing an SMTP-sending plugin (WP Mail SMTP, Post SMTP, FluentSMTP, and others all work) configured against a real transactional mail provider, and adding SPF/DMARC records for the domain you send from at your DNS host.'=>'فحص تشخيصي فقط — لا يغيّر أي شيء هنا طريقة إرسال البريد. على الاستضافة العادية (PHP mail()، دون إضافة SMTP)، من المرجح بشكل متزايد أن يصل البريد المرسل من عنوان لا يطابق نطاق موقعك نفسه، أو من نطاق لا يحتوي على سجل SPF/DMARC أصلًا، إلى البريد غير المرغوب فيه أو يُرفض مباشرةً من مزودي صناديق البريد الكبار. إذا بدا أي صف أدناه غير صحيح، فإن الإصلاح الأكثر موثوقية هو تثبيت إضافة لإرسال SMTP (WP Mail SMTP وPost SMTP وFluentSMTP وغيرها كلها تعمل) مهيأة مع مزود بريد معاملات حقيقي، وإضافة سجلات SPF/DMARC للنطاق الذي ترسل منه لدى مزود DNS الخاص بك.','From identity'=>'هوية المرسل','Domain matches site?'=>'هل يتطابق النطاق مع الموقع؟','SPF record'=>'سجل SPF','DMARC record'=>'سجل DMARC','SMTP plugin'=>'إضافة SMTP','Detected: %s'=>'تم اكتشافه: %s','None of the common SMTP-sending plugins were detected — this site is likely relying on PHP\'s built-in mail(), which most hosts deliver poorly through.'=>'لم يتم اكتشاف أيٍّ من إضافات إرسال SMTP الشائعة — من المرجح أن هذا الموقع يعتمد على mail() المدمجة في PHP، والتي يقدّم عبرها معظم مزودي الاستضافة خدمة بريد ضعيفة.','Send a real test email to:'=>'إرسال رسالة اختبار حقيقية إلى:','Send Test'=>'إرسال اختبار','Sends one plain-text email from the same community identity used for review/vote/vouch mail. Reaching your inbox is a good sign; landing in spam or not arriving at all confirms a real deliverability problem regardless of what the checks above say.'=>'يرسل رسالة بريد إلكتروني نصية واحدة من نفس هوية المجتمع المستخدمة للبريد الخاص بالمراجعة/التصويت/التزكية. وصولها إلى صندوق الوارد لديك علامة جيدة؛ أما وصولها إلى البريد غير المرغوب فيه أو عدم وصولها إطلاقًا فيؤكد وجود مشكلة حقيقية في قابلية التسليم بغض النظر عما تقوله الفحوصات أعلاه.','Found'=>'موجود','Not found'=>'غير موجود','DNS lookup failed'=>'فشل بحث DNS','Unavailable on this host'=>'غير متاح على هذا الخادم','No address configured'=>'لا يوجد عنوان مُهيأ','[TEST] Deliverability check from %s'=>'[اختبار] فحص قابلية التسليم من %s','This is a one-off deliverability test from your Agnosis Settings → Email Inbox page. If you\'re reading this in your inbox (not spam), the community/transactional From identity is deliverable to this address.'=>'هذا اختبار قابلية تسليم لمرة واحدة من صفحة إعدادات Agnosis ← البريد الوارد. إذا كنت تقرأ هذه الرسالة في صندوق الوارد لديك (وليس في البريد غير المرغوب فيه)، فإن هوية المرسل المجتمعية/المعاملاتية قابلة للتسليم إلى هذا العنوان.','Pending Applications'=>'الطلبات المعلقة','%d application is awaiting email confirmation from the applicant and isn\'t listed below yet.'=>'%d طلب بانتظار تأكيد البريد الإلكتروني من المتقدم ولم يُدرج أدناه بعد.' . "\0" . '%d طلبات بانتظار تأكيد البريد الإلكتروني من المتقدم ولم تُدرج أدناه بعد.' . "\0" . '' . "\0" . '' . "\0" . '' . "\0" . '','No pending applications.'=>'لا توجد طلبات معلقة.','%d positive vote(s) currently required for admission.'=>'%d من الأصوات الإيجابية مطلوبة حاليًا للقبول.','Applicant'=>'المتقدم','Applied'=>'تاريخ التقديم','Votes'=>'الأصوات','Bio / Portfolio'=>'السيرة / المعرض','%1$d / %2$d'=>'%1$d / %2$d','Portfolio ↗'=>'المعرض ↗','Admit'=>'قبول','Reject'=>'رفض','No admitted members yet.'=>'لا يوجد أعضاء مقبولون بعد.','Joined'=>'منضم','Banned until %s'=>'محظور حتى %s','Banned'=>'محظور','Active'=>'نشط','This address has bounced or been reported as spam — mail may no longer be reaching this artist.'=>'هذا العنوان ارتدّ أو تم الإبلاغ عنه كرسالة غير مرغوب فيها — قد لا تعود الرسائل تصل إلى هذا الفنان.','⚠ %d bounce'=>'⚠ %d ارتداد' . "\0" . '⚠ %d ارتدادات' . "\0" . '' . "\0" . '' . "\0" . '' . "\0" . '','This artist has muted community broadcast messages.'=>'لقد كتم هذا الفنان رسائل البث المجتمعية.','🔇 Broadcasts muted'=>'🔇 البث مكتوم','This artist receives one daily digest of open applications instead of an email per application.'=>'يتلقى هذا الفنان ملخّصًا يوميًا واحدًا من الطلبات المفتوحة بدلًا من رسالة إلكترونية لكل طلب.','📬 Vote digest mode'=>'📬 وضع ملخّص التصويت','Leave the date blank to ban indefinitely. Continue?'=>'اترك التاريخ فارغًا لحظر غير محدد المدة. المتابعة؟','Leave blank to ban indefinitely'=>'اتركه فارغًا للحظر غير المحدد المدة','Suspend'=>'إيقاف مؤقت','Permanently delete this artist and all their content? This cannot be undone.'=>'حذف هذا الفنان وجميع محتواه نهائيًا؟ لا يمكن التراجع عن هذا.','Open a community removal vote for this artist? All members will be emailed.'=>'فتح تصويت مجتمعي لإزالة هذا الفنان؟ سيتم إرسال بريد إلكتروني إلى جميع الأعضاء.','Open Vote'=>'فتح تصويت','Newsletter Status'=>'حالة النشرة الإخبارية','You have %1$d confirmed public subscribers, above the configured comfort threshold of %2$d. Self-hosted sending still works, but you may want to connect an email service provider (e.g. Brevo\'s free tier) for better deliverability at this size.'=>'لديك %1$d من المشتركين العامين المؤكدين، وهو أعلى من حد الراحة المُعدّ مسبقًا البالغ %2$d. لا يزال الإرسال المستضاف ذاتيًا يعمل، لكن قد ترغب في ربط مزوّد خدمة بريد إلكتروني (مثل الخطة المجانية من Brevo) لتحسين قابلية التسليم بهذا الحجم.','Audience'=>'الجمهور','Last sent'=>'آخر إرسال','Action'=>'الإجراء','Failed recipients'=>'المستلمون الذين فشلوا','Send a test'=>'إرسال اختبار','%1$d admitted (%2$d opted out)'=>'%1$d تم قبوله (%2$d انسحبوا)','Sending…'=>'جارٍ الإرسال…','Idle'=>'خامل','Send Now'=>'أرسل الآن','Public'=>'عام','%1$d confirmed, %2$d pending confirmation, %3$d unsubscribed, %4$d bounced'=>'%1$d مؤكد، %2$d بانتظار التأكيد، %3$d ألغوا الاشتراك، %4$d ارتدّوا','By language: %s'=>'حسب اللغة: %s','Add the "Newsletter Signup" block to any page to let visitors subscribe to the public newsletter. Artists are enrolled automatically and can unsubscribe from any issue with one click.'=>'أضِف كتلة "Newsletter Signup" إلى أي صفحة للسماح للزوار بالاشتراك في النشرة الإخبارية العامة. يتم تسجيل الفنانين تلقائيًا ويمكنهم إلغاء الاشتراك من أي عدد بنقرة واحدة.','Never'=>'أبدًا','Unknown'=>'غير معروف','None'=>'لا شيء','%d failed'=>'%d فشل' . "\0" . '%d فشل' . "\0" . '' . "\0" . '' . "\0" . '' . "\0" . '','Retry Failed'=>'إعادة محاولة الفاشلة','Invite an Artist'=>'دعوة فنان','Send a one-off email inviting someone to apply. Nothing is tracked or scheduled — this sends immediately to the address below.'=>'أرسل رسالة إلكترونية لمرة واحدة لدعوة شخص ما للتقديم. لا يتم تتبع أي شيء أو جدولته — سيتم الإرسال فورًا إلى العنوان أدناه.','artist@example.com'=>'artist@example.com','Send Invitation'=>'إرسال الدعوة','Permission denied.'=>'تم رفض الإذن.','OpenAI API key not configured.'=>'مفتاح OpenAI API غير مُهيأ.','OpenAI connection successful.'=>'تم الاتصال بـ OpenAI بنجاح.','Anthropic API key not configured.'=>'مفتاح Anthropic API غير مُهيأ.','Anthropic connection successful.'=>'تم الاتصال بـ Anthropic بنجاح.','WordPress AI Client requires WordPress 7.0 or later.'=>'يتطلب WordPress AI Client إصدار WordPress 7.0 أو أحدث.','No text-generation model configured. Set one up under Settings → Connectors.'=>'لم يتم إعداد أي نموذج لتوليد النصوص. قم بإعداد واحد من خلال الإعدادات → الموصلات.','WordPress AI Client is available and a text-generation model is configured.'=>'WordPress AI Client متاح وتم إعداد نموذج لتوليد النصوص.','Unknown provider.'=>'مزوّد غير معروف.','HTTP %d'=>'HTTP %d','The artist sent no subject line or message with this submission — let the image speak entirely for itself.'=>'لم يرسل الفنان سطر موضوع أو رسالة مع هذا التقديم — دع الصورة تتحدث عن نفسها بالكامل.','Name'=>'الاسم','Bio'=>'السيرة','Statement'=>'البيان','%1$s must be %2$d characters or fewer.'=>'يجب أن يكون %1$s مكوّنًا من %2$d حرفًا أو أقل.','Please select your language.'=>'يرجى اختيار لغتك.','An account with this email address already exists.'=>'يوجد حساب بهذا البريد الإلكتروني بالفعل.','This email address belongs to an admitted artist.'=>'ينتمي عنوان البريد الإلكتروني هذا إلى فنانٍ مقبول.','An application for this email address is already pending.'=>'يوجد طلب قيد الانتظار لهذا العنوان الإلكتروني بالفعل.','Application not found.'=>'لم يتم العثور على الطلب.','Only admitted artists can vouch.'=>'يمكن للفنانين المقبولين فقط تزكية الآخرين.','Admin access required.'=>'مطلوب وصول إداري.','You cannot vote on your own application.'=>'لا يمكنك التصويت على طلبك الخاص.','Invalid or incomplete link.'=>'رابط غير صالح أو غير مكتمل.','This confirmation link is invalid or has already been used.'=>'رابط التأكيد هذا غير صالح أو تم استخدامه بالفعل.','Confirm your application?'=>'تأكيد طلبك؟','Your application will open for community review once you confirm below.'=>'سيفتح طلبك للمراجعة من قبل المجتمع بمجرد أن تؤكّد أدناه.','Confirm my application'=>'تأكيد طلبي','This community is currently full, so your application has joined the waitlist — when a member leaves, the next person in line is welcomed in.'=>'هذا المجتمع ممتلئ حاليًا، لذا تمت إضافة طلبك إلى قائمة الانتظار — وعندما يغادر أحد الأعضاء، يُرحَّب بأول شخص في الطابور.','You\'re all set — the community can now review your application and vote.'=>'أنت جاهز — يمكن للمجتمع الآن مراجعة طلبك والتصويت.','Application confirmed'=>'تم تأكيد الطلب','Thanks, %s!'=>'شكرًا لك، %s!','Link error'=>'خطأ في الرابط','Confirm your application to %s'=>'تأكيد طلبك للانضمام إلى %s','Your application to %s'=>'طلبك إلى %s','Application by %s has closed'=>'أُغلق طلب %s','Welcome to %s'=>'مرحبًا بك في %s','We received your application to %s'=>'لقد تلقّينا طلبك إلى %s','Hi %s,'=>'مرحبًا %s،','One last step before %s can review your application: confirm this is really your email address.'=>'خطوة أخيرة قبل أن تتمكّن %s من مراجعة طلبك: أكّد أن هذا هو عنوان بريدك الإلكتروني فعلًا.','If you didn\'t apply, simply ignore this email — nothing happens until this link is clicked.'=>'إذا لم تكن قد قدّمت طلبًا، فما عليك سوى تجاهل هذا البريد الإلكتروني — لن يحدث شيء حتى يتم النقر على هذا الرابط.','%s — art blooming out of oblivion'=>'%s — فنّ يزهر من العدم','Thank you for applying to %s. Your application has been received and is now open for community review.'=>'شكرًا لتقديمك طلبًا إلى %s. لقد استلمنا طلبك وأصبح الآن مفتوحًا لمراجعة المجتمع.','The community has %d days to vote. We will let you know the outcome by email.'=>'لدى المجتمع %d يومًا للتصويت. سنُعلمك بالنتيجة عبر البريد الإلكتروني.','New application: %1$s wants to join %2$s'=>'طلب جديد: %1$s يريد الانضمام إلى %2$s','%1$s has applied to join %2$s. You have %3$d days to vote.'=>'قدّم %1$s طلبًا للانضمام إلى %2$s. لديك %3$d أيام للتصويت.','Portfolio:'=>'الملف الفني:','Vote YES'=>'صوّت بنعم','Vote NO'=>'صوّت بلا','You can change your vote at any time within the voting window.'=>'يمكنك تغيير صوتك في أي وقت ضمن فترة التصويت.','Thank you for applying to %s. Unfortunately, your application did not receive enough votes within the voting window.'=>'شكرًا لتقديمك طلبًا إلى %s. للأسف، لم يحصل طلبك على عدد كافٍ من الأصوات ضمن فترة التصويت.','You are welcome to apply again in the future.'=>'يمكنك التقدّم مرة أخرى في المستقبل.','The application by %s has closed without reaching the admission threshold. No action required.'=>'أُغلق طلب %s دون الوصول إلى عتبة القبول. لا يلزم اتخاذ أي إجراء.','The %s community has admitted you as an artist. Welcome!'=>'لقد قبِلك مجتمع %s كفنان. أهلاً بك!','Your gallery:'=>'معرضك:','Your submissions:'=>'إرسالاتك:','How to share your work — send an email to:'=>'كيفية مشاركة عملك — أرسل بريدًا إلكترونيًا إلى:','Subject line conventions:'=>'قواعد سطر الموضوع:','Artwork (default) — any subject'=>'عمل فني (افتراضي) — أي موضوع','[Biography] — biography update'=>'[السيرة الذاتية] — تحديث السيرة الذاتية','[Event] — event announcement'=>'[فعالية] — إعلان فعالية','[Photo] — publish as-is, no AI enhancement (fallback for mail apps without To: aliases)'=>'[صورة] — انشر كما هو، دون تحسين بالذكاء الاصطناعي (بديل لتطبيقات البريد التي لا تدعم أسماء To: المستعارة)','[Pure] — publish exactly as sent, no AI at all (fallback for mail apps without To: aliases)'=>'[نقي] — انشر تمامًا كما أُرسل، دون أي ذكاء اصطناعي (بديل لتطبيقات البريد التي لا تدعم أسماء To: المستعارة)','To leave the network and delete your account:'=>'لمغادرة الشبكة وحذف حسابك:','Send any email (no attachment needed). You will receive a confirmation link — nothing is deleted until you click it.'=>'أرسل أي رسالة بريد إلكتروني (لا حاجة إلى مرفق). ستتلقى رابط تأكيد — لن يُحذف شيء حتى تنقر عليه.','No login is needed to work with Agnosis — everything above happens by email. If you\'d also like to use the site\'s optional online features (like previewing a submission before it publishes), you can set up a password whenever you like using'=>'لا يلزم تسجيل دخول للعمل مع Agnosis — كل ما سبق يحدث عبر البريد الإلكتروني. وإذا أردت أيضًا استخدام الميزات الاختيارية عبر الموقع (مثل معاينة الإرسال قبل نشره)، يمكنك إعداد كلمة مرور متى شئت باستخدام','password recovery'=>'استعادة كلمة المرور','Submit artwork'=>'إرسال عمل فني','Submit biography'=>'إرسال سيرة ذاتية','Submit event'=>'إرسال فعالية','Replace artwork (subject: exact title)'=>'استبدال العمل الفني (الموضوع: العنوان الدقيق)','Remove artwork (subject: exact title)'=>'إزالة العمل الفني (الموضوع: العنوان الدقيق)','Feature artwork in the shared gallery (subject: exact title)'=>'عرض العمل الفني في المعرض المشترك (الموضوع: العنوان الدقيق)','Photo-only — publish as-is, no AI enhancement'=>'لصور فقط — انشر كما هو، دون تحسين بالذكاء الاصطناعي','Pure — publish exactly as sent, no AI at all'=>'نقي — انشر تمامًا كما أُرسل، دون أي ذكاء اصطناعي','About %s'=>'حول %s','%1$s — %2$s'=>'%1$s — %2$s','[%s] Your community message was not sent — too long'=>'[%s] لم تُرسل رسالتك إلى المجتمع — طويلة جدًا','Hi %1$s,

Your message to the community was %2$d characters long — the current limit is %3$d. It was not sent to anyone.

Every recipient\'s copy is translated individually into their own language, so a very long message is costly to translate for the whole community. Please shorten it and send it again.

— %4$s'=>'مرحبًا %1$s،

كانت رسالتك إلى المجتمع بطول %2$d حرفًا — والحد الحالي هو %3$d. لم تُرسل إلى أي أحد.

تُترجم نسخة كل مستلم بشكل فردي إلى لغته الخاصة، لذا فإن الرسالة الطويلة جدًا مكلفة في ترجمتها للمجتمع بأكمله. يرجى اختصارها وإرسالها مرة أخرى.

— %4$s','[%s] Your community message was not sent — no content found'=>'[%s] لم تُرسل رسالتك إلى المجتمع — لم يتم العثور على محتوى','Hi %1$s,

Your message to the community had no subject or message text that could be found — this often happens when an email client sends an HTML-only message with no plain-text version included. It was not sent to anyone.

Please try sending it again with plain text included.

— %2$s'=>'مرحبًا %1$s،

لم تحتوي رسالتك إلى المجتمع على موضوع أو نص رسالة يمكن العثور عليه — ويحدث هذا غالبًا عندما يرسل عميل البريد رسالة بــ HTML فقط دون تضمين نسخة نصية عادية. لم تُرسل إلى أي أحد.

يرجى المحاولة مرة أخرى مع تضمين نص عادي.

— %2$s','[%1$s] Community message from %2$s'=>'[%1$s] رسالة المجتمع من %2$s','%1$s <%2$s> sent a message to the community:'=>'أرسل %1$s <%2$s> رسالة إلى المجتمع:','Subject: %s'=>'الموضوع: %s','Hit reply to respond — your reply goes back to the whole community, translated automatically, just like this message.'=>'اضغط على رد للرد — سيعود ردك إلى المجتمع بأكمله، مترجمًا تلقائيًا، تمامًا مثل هذه الرسالة.','This message was sent by %s.'=>'أُرسلت هذه الرسالة بواسطة %s.','%1$s via %2$s'=>'%1$s عبر %2$s','no limit'=>'بدون حد','Hi %1$s,

The %2$s community has opened a vote to change the membership size cap to %3$s. The vote closes on %4$s.

A strict majority of active members (more than 50%%) must vote yes for the new cap to be adopted. Sign in to your account to cast your vote.

— %2$s'=>'مرحبًا %1$s،

فتح مجتمع %2$s تصويتًا لتغيير الحد الأقصى لحجم العضوية إلى %3$s. يُغلق التصويت في %4$s.

يجب أن تصوت الأغلبية الصريحة للأعضاء النشطين (أكثر من 50%%) بنعم لاعتماد الحد الجديد. سجّل الدخول إلى حسابك للإدلاء بصوتك.

— %2$s','Community size-cap vote open at %s'=>'فتح تصويت الحد الأقصى لحجم المجتمع في %s','Community size cap changed at %s'=>'تغيير الحد الأقصى لحجم المجتمع في %s','The community voted to change the membership size cap to %1$s (proposal #%2$d). The new cap is now in effect.'=>'صوّت المجتمع لتغيير الحد الأقصى لحجم العضوية إلى %1$s (الاقتراح رقم #%2$d). أصبح الحد الجديد ساري المفعول الآن.','Community size-cap proposal did not pass at %s'=>'فشل اقتراح تغيير الحد الأقصى لحجم المجتمع في %s','A community vote to change the membership size cap (proposal #%1$d) closed without a majority. The cap is unchanged.'=>'أُغلق تصويت مجتمعي لتغيير الحد الأقصى لحجم العضوية (الاقتراح رقم #%1$d) دون الحصول على أغلبية. ولم يتغير الحد.','Only community members can do this.'=>'يمكن لأعضاء المجتمع فقط القيام بذلك.','The cap must be zero or a positive number.'=>'يجب أن يكون الحد صفرًا أو عددًا موجبًا.','That is already the current cap.'=>'هذا هو بالفعل الحد الحالي.','A different cap proposal is already under way. Resolve or co-sign that one first.'=>'هناك بالفعل اقتراح آخر لتغيير الحد قيد التنفيذ. عالجه أو شارك في توقيعه أولًا.','No active proposal to co-sign.'=>'لا يوجد اقتراح نشط للمشاركة في توقيعه.','Proposal not found.'=>'لم يتم العثور على الاقتراح.','This vote is not currently open.'=>'هذا التصويت غير مفتوح حاليًا.','This artist can\'t be reached through this form right now.'=>'لا يمكن الوصول إلى هذا الفنان عبر هذا النموذج الآن.','Thanks — your message has been sent.'=>'شكرًا — تم إرسال رسالتك.','Spam, scams, or unsolicited commercial advertising unrelated to genuinely contacting the artist about their work'=>'رسائل مزعجة، أو عمليات احتيال، أو إعلانات تجارية غير مرغوب فيها لا علاقة لها بالتواصل الحقيقي مع الفنان بشأن أعماله','Flagged by automatic content review.'=>'تم وسمها من خلال المراجعة التلقائية للمحتوى.','New message from %s via your Agnosis contact form'=>'رسالة جديدة من %s عبر نموذج الاتصال في Agnosis','From: %s'=>'من: %s','(no name provided)'=>'(لم يتم تقديم اسم)','Email: %s'=>'البريد الإلكتروني: %s','Original message, as submitted:'=>'الرسالة الأصلية كما تم إرسالها:','Your name (optional)'=>'اسمك (اختياري)','Your email address'=>'عنوان بريدك الإلكتروني','you@example.com'=>'you@example.com','Send message'=>'إرسال الرسالة','Thanks — your message has been sent. You can reach out to this artist again a little later.'=>'شكرًا — تم إرسال رسالتك. يمكنك التواصل مع هذا الفنان مرة أخرى بعد قليل.','Something went wrong. Please try again.'=>'حدث خطأ ما. يُرجى المحاولة مرة أخرى.','Authentication required.'=>'يلزم تسجيل الدخول.','This field cannot be edited here.'=>'لا يمكن تعديل هذا الحقل هنا.','That date could not be understood.'=>'لم يمكن فهم هذا التاريخ.','That does not look like a valid timezone (e.g. "Europe/Madrid").'=>'لا يبدو هذا نطاقًا زمنيًا صالحًا (مثل "Europe/Madrid").','That does not look like a valid link (must start with http:// or https://).'=>'لا يبدو هذا رابطًا صالحًا (يجب أن يبدأ بـ http:// أو https://).','The title cannot be empty.'=>'لا يمكن أن يكون العنوان فارغًا.','Saved — translations will update within a few minutes.'=>'تم الحفظ — ستتحدّث الترجمات خلال بضع دقائق.','No image file was received.'=>'لم يتم استلام أي ملف صورة.','Please upload a JPEG, PNG, WebP, or GIF image.'=>'يُرجى رفع صورة بصيغة JPEG أو PNG أو WebP أو GIF.','The uploaded file could not be read.'=>'تعذّر قراءة الملف الذي تم رفعه.','Untitled'=>'بدون عنوان','Photo replaced — the original is kept and can be restored later.'=>'تم استبدال الصورة — تم الاحتفاظ بالأصل ويمكن استعادته لاحقًا.','There is no photo to restore.'=>'لا توجد صورة لاستعادتها.','No earlier version of this photo was found.'=>'لم يتم العثور على إصدار أقدم من هذه الصورة.','Restored the earlier photo.'=>'تمت استعادة الصورة الأقدم.','Only admitted artists may edit their own content.'=>'يُسمح فقط للفنانين المقبولين بتعديل محتواهم الخاص.','Content not found.'=>'المحتوى غير موجود.','Only published content can be corrected here.'=>'لا يمكن تصحيح سوى المحتوى المنشور هنا.','You may only edit your own content.'=>'لا يمكنك تعديل سوى محتواك الخاص.','This page is not in your own language. Edit the version in your language instead.'=>'هذه الصفحة ليست بلغتك الخاصة. يُرجى تعديل النسخة بلغتك بدلًا من ذلك.','Unsupported field target.'=>'وجهة الحقل غير مدعومة.','Save'=>'حفظ','Cancel'=>'إلغاء','Saving…'=>'جارٍ الحفظ…','Replace photo'=>'استبدال الصورة','Uploading…'=>'جارٍ الرفع…','Restore earlier photo'=>'استعادة الصورة السابقة','Restoring…'=>'جارٍ الاستعادة…','You have left'=>'لقد غادرت','Your account and everything you published on %s have been permanently deleted. Nothing tied to you is stored here anymore.'=>'تم حذف حسابك وكل ما نشرته على %s نهائيًا. لم يعد هناك أي شيء مرتبط بك مخزن هنا.','Link expired or already used'=>'انتهت صلاحية الرابط أو تم استخدامه بالفعل','This confirmation link has already been used or is no longer valid. If you still want to leave, please request removal again from your account.'=>'تم استخدام رابط التأكيد هذا بالفعل أو لم يعد صالحًا. إذا كنت لا تزال ترغب في المغادرة، فيُرجى طلب الإزالة مرة أخرى من حسابك.','You must be logged in.'=>'يجب أن تكون مسجّل الدخول.','Artist access required.'=>'يتطلب ذلك صلاحيات الفنان.','No active membership found for this account.'=>'لم يتم العثور على عضوية نشطة لهذا الحساب.','You cannot nominate yourself for removal.'=>'لا يمكنك ترشيح نفسك للإزالة.','Artist not found.'=>'لم يتم العثور على الفنان.','Removal request not found.'=>'لم يتم العثور على طلب الإزالة.','You cannot vote on your own removal.'=>'لا يمكنك التصويت على إزالتك الخاصة.','Confirm your departure from %s'=>'تأكيد مغادرتك لـ %s','Hi %1$s,

We received a request to remove your account and all your published work from %2$s.

If you made this request, click the link below to confirm. This action is permanent and cannot be undone.

%3$s

If you did not make this request, you can ignore this email — your account remains unchanged.

— %2$s'=>'مرحبًا %1$s،

لقد تلقّينا طلبًا لإزالة حسابك وكل أعمالك المنشورة من %2$s.

إذا كنت أنت من قدّم هذا الطلب، فانقر على الرابط أدناه للتأكيد. هذا الإجراء نهائي ولا يمكن التراجع عنه.

%3$s

إذا لم تكن أنت من قدّم هذا الطلب، يمكنك تجاهل هذا البريد الإلكتروني — سيبقى حسابك دون تغيير.

— %2$s','An artist has left %s'=>'غادر أحد الفنانين %s','%1$s has confirmed their departure from %2$s.

Their account and all published work have been permanently deleted.

— %2$s'=>'%1$s أكد مغادرته/مغادرتها من %2$s.

تم حذف حسابه/حسابها وكل الأعمال المنشورة نهائيًا.

— %2$s','You\'ve left %s'=>'لقد غادرت %s','Hi %1$s,

This confirms that your account and everything you published on %2$s have been permanently deleted, as you requested.

Nothing tied to you — your artwork, biography, events, or account details — is stored on %2$s anymore.

If you didn\'t request this, please contact the site admin right away.

— %2$s'=>'مرحبًا %1$s،

يؤكد هذا أنه تم حذف حسابك وكل ما نشرته على %2$s نهائيًا، كما طلبت.

لم يعد هناك أي شيء مرتبط بك — أعمالك الفنية، أو سيرتك الذاتية، أو الفعاليات، أو تفاصيل حسابك — محفوظًا على %2$s.

إذا لم تكن قد طلبت ذلك، يُرجى الاتصال بمسؤول الموقع فورًا.

— %2$s','Hi %1$s,

Your membership at %2$s has been temporarily suspended until %3$s.

You will be automatically reinstated on that date. If you have questions, please contact the site admin.

— %2$s'=>'مرحبًا %1$s،

تم تعليق عضويتك في %2$s مؤقتًا حتى %3$s.

سيتم إعادة تفعيل عضويتك تلقائيًا في ذلك التاريخ. إذا كانت لديك أسئلة، يُرجى الاتصال بمسؤول الموقع.

— %2$s','Hi %1$s,

Your membership at %2$s has been suspended.

If you have questions, please contact the site admin.

— %2$s'=>'مرحبًا %1$s،

تم تعليق عضويتك في %2$s.

إذا كانت لديك أسئلة، يُرجى الاتصال بمسؤول الموقع.

— %2$s','Your membership at %s has been suspended'=>'تم تعليق عضويتك في %s','Hi %1$s,

Your temporary suspension at %2$s has ended and your membership has been reinstated. You can now log in and submit work as before.

— %2$s'=>'مرحبًا %1$s،

انتهى تعليقك المؤقت في %2$s، وتمت إعادة تفعيل عضويتك. يمكنك الآن تسجيل الدخول وإرسال الأعمال كما كان من قبل.

— %2$s','Your membership at %s has been reinstated'=>'تمت إعادة تفعيل عضويتك في %s','Hi %1$s,

The %2$s community has opened a vote to remove a member. The vote closes on %3$s.

Cast your vote:

Vote YES (remove): %4$s

Vote NO (keep):    %5$s

A majority of active members (more than 50%%) must vote yes for the removal to proceed. You can change your vote by clicking the other link before the deadline.

— %2$s'=>'مرحبًا %1$s،

فتحت جماعة %2$s تصويتًا لإزالة أحد الأعضاء. ينتهي التصويت في %3$s.

أدلِ بصوتك:

صوّت بنعم (إزالة): %4$s

صوّت بلا (الإبقاء): %5$s

يجب أن يصوّت الأغلبية من الأعضاء النشطين (أكثر من 50%%) بنعم حتى تتم الإزالة. يمكنك تغيير صوتك بالنقر على الرابط الآخر قبل الموعد النهائي.

— %2$s','Community removal vote open at %s'=>'فتح تصويت إزالة من المجتمع في %s','Community removal vote passed at %s'=>'تم تمرير تصويت إزالة من المجتمع في %s','The community removal vote has closed with a majority in favor.

The artist\'s account and all published work have been permanently deleted from %1$s.

— %2$s'=>'أُغلق تصويت إزالة المجتمع مع أغلبية مؤيدة.

تم حذف حساب الفنان وكل الأعمال المنشورة نهائيًا من %1$s.

— %2$s','Community removal vote did not pass at %s'=>'لم ينجح تصويت إزالة المجتمع في %s','The community removal vote has closed. The required majority was not reached and the artist\'s membership remains active.

— %s'=>'أُغلق تصويت إزالة المجتمع. لم تتحقق الأغلبية المطلوبة وتظل عضوية الفنان نشطة.

— %s','Please enter a valid email address.'=>'يرجى إدخال عنوان بريد إلكتروني صالح.','wp_mail() reported a failure — check your site\'s outgoing mail configuration.'=>'أبلغت wp_mail() عن فشل — تحقّق من إعدادات البريد الصادر في موقعك.','You\'re invited to join %s'=>'أنت مدعو للانضمام إلى %s','[TEST] %s'=>'[اختبار] %s','You\'re invited'=>'أنت مدعو','Apply to join'=>'قدّم طلب انضمام','No account needed to apply — the community reviews and votes on every application.'=>'لا حاجة إلى حساب لتقديم الطلب — يقوم المجتمع بمراجعة كل طلب والتصويت عليه.','You are already an admitted Agnosis artist.'=>'أنت بالفعل فنان/فنانة معتمد/معتمدة في Agnosis.','Your name'=>'اسمك','required'=>'مطلوب','Email address'=>'عنوان البريد الإلكتروني','Short bio'=>'نبذة قصيرة','A few sentences about your practice, medium, and background.'=>'بضع جمل عن ممارستك، والوسيط الذي تعمل به، وخلفيتك.','Portfolio URL'=>'رابط الملف الفني','Why do you want to join?'=>'لماذا ترغب في الانضمام؟','Language you work in'=>'اللغة التي تعمل بها','Select your language'=>'اختر لغتك','Helps us communicate and translate content in your language.'=>'يساعدنا ذلك على التواصل وترجمة المحتوى إلى لغتك.','Apply'=>'قدّم الطلب','Almost there — check your inbox for a confirmation email and click the link to open your application for community review.'=>'اقتربت من النهاية — تحقّق من صندوق الوارد لديك بحثًا عن رسالة تأكيد إلكترونية، ثم انقر الرابط لفتح طلبك لمراجعته من المجتمع.','Please fill in all required fields.'=>'يرجى ملء جميع الحقول المطلوبة.','This preferences link is invalid or has been tampered with.'=>'رابط التفضيلات هذا غير صالح أو تم العبث به.','This preferences link is no longer valid for this account.'=>'رابط التفضيلات هذا لم يعد صالحًا لهذا الحساب.','Notification preferences'=>'تفضيلات الإشعارات','Mute community broadcast messages from other artists.'=>'كتم رسائل البث المجتمعية من الفنانين الآخرين.','Application vote emails'=>'رسائل التصويت على الطلبات','Instantly, one email per application (default).'=>'فورًا، رسالة إلكترونية واحدة لكل طلب (افتراضي).','Once a day, a single digest of every application still awaiting my vote.'=>'مرة واحدة يوميًا، ملخص واحد لكل الطلبات التي لا تزال تنتظر تصويتي.','Turn off the contact form on my page — visitors won\'t be able to message me.'=>'إيقاف نموذج الاتصال في صفحتي — لن يتمكن الزوار من مراسلتي.','Save preferences'=>'حفظ التفضيلات','Community broadcasts are now muted.'=>'تم الآن كتم رسائل البث المجتمعية.','You\'ll continue to receive community broadcasts.'=>'ستستمر في تلقي رسائل البث المجتمعية.','You\'ll receive one daily digest of applications awaiting your vote.'=>'ستتلقى ملخصًا يوميًا واحدًا للطلبات التي تنتظر تصويتك.','You\'ll receive an email as soon as each new application arrives.'=>'ستتلقى رسالة إلكترونية فور وصول كل طلب جديد.','The contact form on your page is now turned off.'=>'تم الآن إيقاف نموذج الاتصال في صفحتك.','Visitors can still reach you through the contact form on your page.'=>'لا يزال بإمكان الزوار الوصول إليك عبر نموذج الاتصال في صفحتك.','Preferences saved'=>'تم حفظ التفضيلات','Artworks'=>'الأعمال الفنية','Write about this artwork…'=>'اكتب عن هذا العمل الفني…','Biographies'=>'السِّيَر الذاتية','Biography'=>'السيرة الذاتية','Add New Biography'=>'إضافة سيرة ذاتية جديدة','Edit Biography'=>'تعديل السيرة الذاتية','New Biography'=>'سيرة ذاتية جديدة','View Biography'=>'عرض السيرة الذاتية','Search Biographies'=>'البحث في السِّيَر الذاتية','No biographies found.'=>'لم يتم العثور على أي سِيَر ذاتية.','No biographies in trash.'=>'لا توجد سِيَر ذاتية في سلة المهملات.','All Biographies'=>'كل السِّيَر الذاتية','Events'=>'الفعاليات','Event'=>'فعالية','Add New Event'=>'إضافة فعالية جديدة','Edit Event'=>'تعديل الفعالية','New Event'=>'فعالية جديدة','View Event'=>'عرض الفعالية','Search Events'=>'البحث في الفعاليات','No events found.'=>'لم يتم العثور على أي فعاليات.','No events in trash.'=>'لا توجد فعاليات في سلة المهملات.','All Events'=>'كل الفعاليات','Medium'=>'الوسيط','Mediums'=>'الوسائط','Search Mediums'=>'البحث في الوسائط','All Mediums'=>'كل الوسائط','Edit Medium'=>'تعديل الوسيط','Update Medium'=>'تحديث الوسيط','Add New Medium'=>'إضافة وسيط جديد','New Medium Name'=>'اسم الوسيط الجديد','Artwork'=>'عمل فني','Add New'=>'إضافة جديد','Add New Artwork'=>'إضافة عمل فني جديد','Edit Artwork'=>'تعديل العمل الفني','New Artwork'=>'عمل فني جديد','View Artwork'=>'عرض العمل الفني','Search Artworks'=>'البحث في الأعمال الفنية','No artworks found.'=>'لم يتم العثور على أي أعمال فنية.','No artworks in trash.'=>'لا توجد أعمال فنية في سلة المهملات.','All Artworks'=>'كل الأعمال الفنية','Artwork Archives'=>'أرشيف الأعمال الفنية','Artwork Attributes'=>'سمات العمل الفني','Invalid vote link.'=>'رابط التصويت غير صالح.','This vote link is invalid or has been tampered with.'=>'هذا الرابط الخاص بالتصويت غير صالح أو تم التلاعب به.','Voter account not found.'=>'لم يتم العثور على حساب المصوّت.','Vote to remove this artist from the community?'=>'هل تريد التصويت لإزالة هذا الفنان من المجتمع؟','Vote to keep this artist in the community?'=>'هل تريد التصويت للإبقاء على هذا الفنان في المجتمع؟','Your vote will be recorded once you confirm below.'=>'سيتم تسجيل صوتك بمجرد تأكيدك أدناه.','Confirm my vote'=>'تأكيد صوتي','You voted to remove this artist from the community.'=>'لقد صوّتَّ لإزالة هذا الفنان من المجتمع.','You voted to keep this artist in the community.'=>'لقد صوّتَّ للإبقاء على هذا الفنان في المجتمع.','%d vote to remove recorded so far.'=>'تم تسجيل %d صوتًا للإزالة حتى الآن.' . "\0" . 'تم تسجيل %d أصوات للإزالة حتى الآن.' . "\0" . '' . "\0" . '' . "\0" . '' . "\0" . '','Vote recorded'=>'تم تسجيل التصويت','Vote error'=>'خطأ في التصويت','%d application awaiting your vote'=>'%d طلبًا بانتظار تصويتك' . "\0" . '%d طلبات بانتظار تصويتك' . "\0" . '' . "\0" . '' . "\0" . '' . "\0" . '','Here\'s your daily digest of applications to %1$s still awaiting your vote. Each has a %2$d-day voting window from when it was confirmed.'=>'إليك ملخصك اليومي للطلبات إلى %1$s التي لا تزال بانتظار تصويتك. لكلٍ منها نافذة تصويت مدتها %2$d يومًا منذ تأكيدها.','Prefer these one at a time again? You can switch back any time from your notification preferences link below.'=>'تفضّل هذه الطلبات واحدةً تلو الأخرى مرة أخرى؟ يمكنك التبديل في أي وقت من رابط تفضيلات الإشعارات أدناه.','Vote in favor of this application?'=>'هل تريد التصويت بالموافقة على هذا الطلب؟','Vote against this application?'=>'هل تريد التصويت ضد هذا الطلب؟','You voted in favor of this application.'=>'لقد صوّتَّ بالموافقة على هذا الطلب.','You voted against this application.'=>'لقد صوّتَّ ضد هذا الطلب.','%d positive vote recorded so far.'=>'تم تسجيل %d صوت إيجابي حتى الآن.' . "\0" . 'تم تسجيل %d أصوات إيجابية حتى الآن.' . "\0" . '' . "\0" . '' . "\0" . '' . "\0" . '','is active and configured for'=>'نشط ومُعدّ لـ','Subdomain'=>'النطاق الفرعي','routing mode'=>'وضع التوجيه','This conflicts with Agnosis artist subdomains — both plugins would claim the same subdomain namespace.'=>'يتعارض هذا مع النطاقات الفرعية لفناني Agnosis — إذ سيطالب كلا المكوّنين بالمجال نفسه للنطاقات الفرعية.','Artist subdomain routing is'=>'توجيه النطاق الفرعي للفنان','completely inactive'=>'غير نشط تمامًا','until this is resolved.'=>'حتى يتم حل هذا.','Fix: open'=>'الإصلاح: افتح','Settings'=>'الإعدادات','Language Router'=>'موجّه اللغة','and switch the URL strategy to'=>'وغيّر استراتيجية الرابط إلى','Path prefix (subfolder)'=>'بادئة المسار (مجلد فرعي)','This is the LinguaForge default and allows artist subdomains to coexist with language subfolders'=>'هذا هو الإعداد الافتراضي في LinguaForge، ويسمح بتعايش النطاقات الفرعية للفنانين مع المجلدات الفرعية للغات','Agnosis — Artist Subdomain Routing is disabled'=>'Agnosis — تم تعطيل توجيه النطاق الفرعي للفنان','Open LinguaForge Settings'=>'افتح إعدادات LinguaForge','Agnosis Artist'=>'فنان Agnosis','My Submissions'=>'إرسالاتي','Join'=>'انضم','Send new artwork to be published.'=>'أرسل عملًا فنيًا جديدًا لنشره.','Update your artist biography.'=>'حدّث السيرة الذاتية الفنية الخاصة بك.','Announce an upcoming event.'=>'أعلن عن فعالية قادمة.','Replace'=>'استبدال','Send a new version of an existing artwork — subject must match its title.'=>'أرسل نسخة جديدة من عمل فني موجود — يجب أن يطابق الموضوع عنوانه.','Request an existing artwork or event be taken down — subject must match its title.'=>'اطلب إزالة عمل فني أو فعالية موجودة — يجب أن يطابق الموضوع عنوانه.','Promote'=>'إبراز','Choose which artwork represents you in the shared community gallery on the main site — subject must match its title. Your own subdomain already shows everything you\'ve published.'=>'اختر العمل الفني الذي يمثلك في معرض المجتمع المشترك على الموقع الرئيسي — يجب أن يطابق الموضوع عنوانه. نطاقك الفرعي الخاص يعرض بالفعل كل ما نشرته.','Photo-only'=>'صور فقط','Publish a photo exactly as sent — no AI enhancement, no quality check.'=>'انشر صورة كما أُرسلت تمامًا — دون تحسين بالذكاء الاصطناعي، ودون فحص الجودة.','Pure'=>'صِرف','Publish exactly as sent — no AI at all, not even the title/description pass.'=>'انشر تمامًا كما أُرسل — من دون أي ذكاء اصطناعي على الإطلاق، حتى من دون تمرير العنوان/الوصف.','Send a message to every other artist in the community.'=>'أرسل رسالة إلى كل فنان آخر في المجتمع.','Spotted something to fix after publishing? Log in and look for the pencil icon on your published page — you can correct the title, text, or photo yourself, no need to email us again.'=>'وجدت شيئًا يحتاج إلى تصحيح بعد النشر؟ سجّل الدخول وابحث عن أيقونة القلم في صفحتك المنشورة — يمكنك تصحيح العنوان أو النص أو الصورة بنفسك، من دون الحاجة إلى مراسلتنا مرة أخرى.','Manage notification preferences: %s'=>'إدارة تفضيلات الإشعارات: %s','Manage notification preferences'=>'إدارة تفضيلات الإشعارات','Agnosis Membership Application'=>'طلب عضوية Agnosis','Agnosis Governance Participation'=>'المشاركة في حوكمة Agnosis','Agnosis Newsletter Subscription'=>'الاشتراك في نشرة Agnosis البريدية','Agnosis Newsletter Delivery History'=>'سجل تسليم نشرة Agnosis البريدية','Agnosis Contact Messages Sent'=>'الرسائل المرسلة إلى Agnosis','Agnosis Transactions'=>'معاملات Agnosis','Agnosis Notification Preferences'=>'تفضيلات إشعارات Agnosis','Display name'=>'اسم العرض','Application statement'=>'بيان الطلب','Language'=>'اللغة','Applied at'=>'تاريخ التقديم','Resolved at'=>'تاريخ الحل','Type'=>'النوع','Community vouch given'=>'تزكية المجتمع المقدَّمة','Date'=>'التاريخ','Admission vouch given'=>'تزكية القبول المقدَّمة','Community removal vote'=>'تصويت إزالة من المجتمع','Vote'=>'التصويت','Community size-cap vote'=>'تصويت حدّ حجم المجتمع','Locale'=>'الإعدادات المحلية','Subscribed at'=>'تاريخ الاشتراك','Confirmed at'=>'تاريخ التأكيد','Unsubscribed at'=>'تاريخ إلغاء الاشتراك','Issue'=>'الموضوع','Recipient type'=>'نوع المستلم','Queued at'=>'وقت الإضافة إلى قائمة الانتظار','Sent to artist'=>'مُرسل إلى الفنان','Translated message'=>'الرسالة المترجمة','Rejection reason'=>'سبب الرفض','IP address'=>'عنوان IP','Sent at'=>'تاريخ الإرسال','Amount'=>'المبلغ','Currency'=>'العملة','Fee'=>'الرسوم','Gateway'=>'البوابة','Your membership application/account is still active. To remove this data, use the "leave the network" link from any Agnosis email, or ask an administrator.'=>'طلب العضوية/الحساب الخاص بك لا يزال نشطًا. لإزالة هذه البيانات، استخدم رابط "مغادرة الشبكة" من أي رسالة بريدية من Agnosis، أو اطلب من أحد المسؤولين ذلك.','Your biography, statement, and portfolio link were erased. Your email address was kept on file — your account is currently banned, and it\'s the only way this site can continue to enforce that.'=>'تمت إزالة سيرتك الذاتية وبيانك ورابط ملف أعمالك. تم الاحتفاظ بعنوان بريدك الإلكتروني في السجلات — حسابك محظور حاليًا، وهو الطريقة الوحيدة التي يمكن لهذا الموقع من خلالها الاستمرار في تطبيق ذلك.','[message removed]'=>'[تمت إزالة الرسالة]','Vouch messages you wrote were redacted. Governance votes you cast were kept as-is — a vote is a community record, not personal data, and removing it would silently change a settled decision.'=>'تم تنقيح رسائل التزكية التي كتبتها. أما أصوات الحوكمة التي أدليت بها فتم الاحتفاظ بها كما هي — فالصوت يُعد سجلًا مجتمعيًا، وليس بيانات شخصية، وحذفه سيؤدي إلى تغيير قرار مستقر دون أن يظهر ذلك.','Past newsletter delivery records were anonymized; per-issue delivery counts were kept for statistics.'=>'تم إخفاء هوية سجلات تسليم النشرة البريدية السابقة؛ وتم الاحتفاظ بإجماليات التسليم لكل إصدار لأغراض الإحصاء.','Transaction (donation/sale) records were kept in full — financial records are subject to a legal retention obligation and are exempt from erasure under GDPR Art. 17(3)(b).'=>'تم الاحتفاظ بسجلات المعاملات (التبرع/البيع) كاملة — فالسجلات المالية تخضع لالتزام قانوني بالاحتفاظ، وهي مستثناة من الحذف بموجب المادة 17(3)(b) من اللائحة العامة لحماية البيانات (GDPR).','Agnosis is a federated art-publishing plugin. The following is a starting point for describing what it collects — review and adapt it to your site\'s actual configuration before publishing.'=>'Agnosis هو إضافة اتحادية لنشر الأعمال الفنية. فيما يلي نقطة بداية لوصف ما تجمعه — راجعها وعدّلها بما يوافق الإعداد الفعلي لموقعك قبل النشر.','What personal data we collect and why'=>'ما البيانات الشخصية التي نجمعها ولماذا','When you apply to join, we store your email address, display name, biography, statement, and portfolio link to run the community vouching process. When you email us artwork, a biography, or an event, the content of that email (including your address) is stored while it is processed and reviewed. When you subscribe to our newsletter or message an artist through their contact form, we store your email address (and, for contact messages, your IP address) to deliver that message or send you future issues.'=>'عندما تتقدم للانضمام، نخزن عنوان بريدك الإلكتروني واسم العرض والسيرة الذاتية والبيان ورابط ملف الأعمال لأجل تشغيل عملية التزكية المجتمعية. عندما ترسل إلينا أعمالًا فنية أو سيرة ذاتية أو فعالية عبر البريد الإلكتروني، يتم تخزين محتوى ذلك البريد (بما في ذلك عنوانك) أثناء معالجته ومراجعته. عندما تشترك في نشرتنا البريدية أو تراسل فنانًا عبر نموذج الاتصال الخاص به، نخزن عنوان بريدك الإلكتروني (ولرسائل الاتصال أيضًا عنوان IP الخاص بك) لتسليم تلك الرسالة أو لإرسال الأعداد المستقبلية إليك.','Who we share it with'=>'مع من نشاركها','Submitted artwork descriptions and images may be sent to a third-party AI provider (OpenAI, Anthropic, or Stability AI, depending on this site\'s configuration) to help write publication text and enhance images. Approved posts are also broadcast publicly over ActivityPub (the Fediverse) as part of this plugin\'s core federation feature.'=>'قد تُرسل أوصاف الأعمال الفنية والصور المقدَّمة إلى مزود ذكاء اصطناعي خارجي (OpenAI أو Anthropic أو Stability AI، حسب إعدادات هذا الموقع) للمساعدة في كتابة نص النشر وتحسين الصور. كما تُبث المنشورات المعتمدة علنًا عبر ActivityPub (الفديفيرس) بوصف ذلك جزءًا من ميزة الاتحاد الأساسية في هذه الإضافة.','How long we retain your data'=>'مدة احتفاظنا ببياناتك','Retention varies by data type; see this site\'s administrator for specifics. You can request a copy of, or the erasure of, the personal data described above at any time using this site\'s standard WordPress data request tools.'=>'تختلف مدة الاحتفاظ حسب نوع البيانات؛ راجع مسؤول هذا الموقع للحصول على التفاصيل. يمكنك طلب نسخة من البيانات الشخصية المذكورة أعلاه، أو طلب محوها، في أي وقت باستخدام أدوات طلب البيانات القياسية في ووردبريس الخاصة بهذا الموقع.','Submitted text and images may be processed by a third-party AI provider. Approved posts are published publicly and shared across the Fediverse — this cannot be fully undone later.'=>'قد تتم معالجة النصوص والصور المقدَّمة بواسطة مزود ذكاء اصطناعي خارجي. تُنشر المشاركات المعتمدة علنًا وتُشارك عبر الفديفيرس — ولا يمكن التراجع عن ذلك بالكامل لاحقًا.','Your message may be reviewed by an automated content filter before being sent to the artist.'=>'قد تتم مراجعة رسالتك بواسطة فلتر محتوى آلي قبل إرسالها إلى الفنان.','See our %s for details.'=>'اطّلع على %s لمزيد من التفاصيل.','Privacy Policy'=>'سياسة الخصوصية','Too many requests. Please wait %d seconds and try again.'=>'طلبات كثيرة جدًا. يُرجى الانتظار %d ثانية ثم المحاولة مرة أخرى.','Submission limit reached. Please wait before sending again.'=>'تم الوصول إلى حدّ الإرسال. يُرجى الانتظار قبل الإرسال مرة أخرى.','Please complete the verification check and try again.'=>'يُرجى إكمال التحقق والمحاولة مرة أخرى.','Could not verify you\'re human right now. Please try again in a moment.'=>'تعذّر التحقق من أنك إنسان الآن. يُرجى المحاولة مرة أخرى بعد قليل.','Verification failed. Please try again.'=>'فشل التحقق. يُرجى المحاولة مرة أخرى.','Every 5 minutes'=>'كل 5 دقائق','IMAP credentials are not configured.'=>'بيانات اعتماد IMAP غير مُهيّأة.','Connected successfully. %1$d message(s) in inbox, %2$d unseen.'=>'تم الاتصال بنجاح. يوجد %1$d رسالة(رسائل) في صندوق الوارد، و%2$d غير مقروءة.','Webhook secret not configured.'=>'السرّ الخاص بالـ Webhook غير مُهيّأ.','Invalid or missing webhook signature.'=>'توقيع Webhook غير صالح أو مفقود.','Webhook request timestamp is missing, malformed, or too old.'=>'الطابع الزمني لطلب Webhook مفقود أو غير صالح التنسيق أو قديم جدًا.','This webhook request has already been processed.'=>'تمت معالجة طلب Webhook هذا بالفعل.','OpenSSL is required for HTTP Signature verification.'=>'يلزم OpenSSL للتحقق من توقيع HTTP.','Signature header is required.'=>'ترويسة التوقيع مطلوبة.','Signature header is missing required fields (keyId, headers, signature).'=>'ترويسة التوقيع تفتقد الحقول المطلوبة (keyId, headers, signature).','Request date is too old or too far in the future.'=>'تاريخ الطلب قديم جدًا أو بعيد جدًا في المستقبل.','Signature value is not valid base64.'=>'قيمة التوقيع ليست base64 صالحًا.','HTTP Signature verification failed.'=>'فشل التحقق من توقيع HTTP.','Digest header does not match the request body.'=>'لا تتطابق ترويسة Digest مع نص الطلب.','keyId in Signature header is not a valid URL.'=>'‏keyId في ترويسة التوقيع ليس عنوان URL صالحًا.','Failed to fetch actor document.'=>'تعذّر جلب مستند الفاعل.','Actor document returned a non-200 response.'=>'أعاد مستند الفاعل استجابة غير 200.','Actor document does not contain a publicKey.publicKeyPem field.'=>'لا يحتوي مستند الفاعل على الحقل publicKey.publicKeyPem.','Node URL is required.'=>'عنوان URL للعقدة مطلوب.','Contact %s'=>'التواصل مع %s','Contact this artist'=>'تواصل مع هذا الفنان','Get in touch with %s'=>'تواصل مع %s','Get in touch'=>'تواصل','This newsletter issue could not be found.'=>'تعذّر العثور على هذا العدد من النشرة.','Issue not found'=>'العدد غير موجود','Newsletter archive'=>'أرشيف النشرة البريدية','Past issues of the %s newsletter.'=>'الأعداد السابقة من نشرة %s البريدية.','No issues have gone out yet — check back soon.'=>'لم تُرسل أي أعداد بعد — تحقّق لاحقًا قريبًا.','← Newer'=>'← الأحدث','Older →'=>'الأقدم →','Newsletter archive — %s'=>'أرشيف النشرة البريدية — %s','%1$s Newsletter — %2$s'=>'نشرة %1$s — %2$s','%s Newsletter'=>'نشرة %s البريدية','Nothing new to report this time — but the community is still here, and the next issue will have more.'=>'لا جديد نعلنه هذه المرة — لكن المجتمع ما زال هنا، والعدد القادم سيحمل المزيد.','New artwork'=>'عمل فني جديد','Upcoming events'=>'فعاليات قادمة','%d new artwork published'=>'نُشر %d عمل فني جديد' . "\0" . 'نُشر %d من الأعمال الفنية الجديدة' . "\0" . '' . "\0" . '' . "\0" . '' . "\0" . '','%d new event announced'=>'أُعلن عن %d فعالية جديدة' . "\0" . 'أُعلنت عن %d فعاليات جديدة' . "\0" . '' . "\0" . '' . "\0" . '' . "\0" . '','Welcome to our newest member: %s'=>'مرحبًا بأحدث عضو لدينا: %s' . "\0" . 'مرحبًا بأحدث أعضائنا: %s' . "\0" . '' . "\0" . '' . "\0" . '' . "\0" . '','%d community vote is open — check your email for your personal voting link.'=>'هناك %d من تصويتات المجتمع مفتوحة — تحقّق من بريدك الإلكتروني للحصول على رابط التصويت الشخصي.' . "\0" . '%d من أصوات المجتمع مفتوحة — تحقّق من بريدك الإلكتروني للحصول على روابط التصويت الخاصة بك.' . "\0" . '' . "\0" . '' . "\0" . '' . "\0" . '','Recent work from the community'=>'أعمال حديثة من المجتمع','…and %d more.'=>'…و%d المزيد.' . "\0" . '…و%d المزيد.' . "\0" . '' . "\0" . '' . "\0" . '' . "\0" . '','Community Newsletter'=>'النشرة الإخبارية للمجتمع','Having trouble viewing this email?'=>'هل تواجه مشكلة في عرض هذا البريد الإلكتروني؟','View it online.'=>'اعرضه عبر الإنترنت.','Unsubscribe'=>'إلغاء الاشتراك','Subscribe to get these by email'=>'اشترك لتصلك هذه عبر البريد الإلكتروني','[%s] Community newsletter'=>'[%s] النشرة الإخبارية للمجتمع','[%s] Newsletter'=>'[%s] النشرة الإخبارية','Get new artworks, artist admissions, and community updates in your inbox.'=>'احصل على أعمال فنية جديدة، وطلبات انضمام الفنانين، وتحديثات المجتمع في صندوق الوارد الخاص بك.','Subscribe to the newsletter'=>'اشترك في النشرة الإخبارية','Unknown newsletter type.'=>'نوع النشرة الإخبارية غير معروف.','A previous issue is still sending — please wait for it to finish.'=>'هناك إصدار سابق لا يزال قيد الإرسال — يرجى الانتظار حتى ينتهي.','Please enter a valid email address to send the test to.'=>'يرجى إدخال عنوان بريد إلكتروني صالح لإرسال الاختبار إليه.','This is a TEST send — it previews the next issue using the current draft intro and recent activity. It was not counted as a real send and no subscribers were emailed. The unsubscribe link below is a non-functional placeholder.'=>'هذا إرسال تجريبي — يعرض معاينة للعدد التالي باستخدام المقدمة المسودة الحالية والنشاط الأخير. لم يُحتسب كإرسال حقيقي ولم تُرسل أي رسائل إلى المشتركين. رابط إلغاء الاشتراك أدناه مجرد عنصر نائب غير وظيفي.','The %1$s at %2$s is due to send in about a day. Agnosis drafted an intro from what\'s new since the last issue:'=>'يُفترض إرسال %1$s في %2$s خلال حوالي يوم. قامت Agnosis بصياغة مقدمة مما هو جديد منذ العدد الأخير:','It\'s already saved and will be used as-is if you don\'t act — review it, rewrite it, or clear it back to blank here:'=>'تم حفظه بالفعل وسيُستخدم كما هو إذا لم تتدخل — راجعه، أو أعد كتابته، أو أعده إلى الفراغ هنا:','%1$s intro drafted for %2$s — review before it sends'=>'تمت صياغة مقدمة %1$s لـ %2$s — راجعها قبل الإرسال','Subscribe'=>'اشترك','See past issues'=>'عرض الأعداد السابقة','Almost there — check your inbox for a confirmation link.'=>'اقتربنا — تحقّق من صندوق الوارد الخاص بك للحصول على رابط التأكيد.','[%s] Confirm your newsletter subscription'=>'[%s] أكّد اشتراكك في النشرة الإخبارية','Thanks for signing up! Confirm your email address to start receiving the newsletter.'=>'شكرًا لتسجيلك! أكّد عنوان بريدك الإلكتروني لبدء تلقي النشرة الإخبارية.','Confirm subscription'=>'تأكيد الاشتراك','If you didn\'t request this, simply ignore this email — you will not be subscribed.'=>'إذا لم تطلب هذا، فما عليك سوى تجاهل هذا البريد الإلكتروني — لن يتم اشتراكك.','Artists are automatically subscribed — there is nothing to confirm.'=>'يتم اشتراك الفنانين تلقائيًا — لا حاجة إلى التأكيد.','Subscription confirmed'=>'تم تأكيد الاشتراك','You\'re all set — the newsletter will land in your inbox from now on.'=>'أصبحت جاهزًا — ستصل النشرة الإخبارية إلى صندوق الوارد الخاص بك من الآن فصاعدًا.','Unsubscribed'=>'تم إلغاء الاشتراك','You will no longer receive the newsletter. Sorry to see you go.'=>'لن تتلقى النشرة الإخبارية بعد الآن. نأسف لرؤيتك تغادر.','This unsubscribe link is invalid or has already been used.'=>'رابط إلغاء الاشتراك هذا غير صالح أو تم استخدامه بالفعل.','This unsubscribe link is invalid or has been tampered with.'=>'رابط إلغاء الاشتراك هذا غير صالح أو تم التلاعب به.','Account not found.'=>'الحساب غير موجود.','You will no longer receive the artist newsletter. You can re-subscribe any time from your submissions page.'=>'لن تتلقى النشرة الإخبارية للفنانين بعد الآن. يمكنك إعادة الاشتراك في أي وقت من صفحة المشاركات الخاصة بك.','Confirm your subscription?'=>'هل تؤكد اشتراكك؟','You\'ll start receiving the newsletter once you confirm below.'=>'ستبدأ في تلقي النشرة الإخبارية بمجرد التأكيد أدناه.','Unsubscribe from the newsletter?'=>'إلغاء الاشتراك من النشرة الإخبارية؟','You will stop receiving the newsletter once you confirm below.'=>'ستتوقف عن تلقي النشرة الإخبارية بمجرد التأكيد أدناه.','Confirm unsubscribe'=>'تأكيد إلغاء الاشتراك','That doesn\'t look like a valid web address.'=>'هذا لا يبدو كعنوان ويب صالح.','This site isn\'t on this Agnosis node\'s list of trusted platforms, and automatic link review is turned off here.'=>'هذا الموقع ليس ضمن قائمة المنصات الموثوقة لهذه العقدة في Agnosis، والمراجعة التلقائية للروابط متوقفة هنا.','This node couldn\'t safely load that page to review it (it may be unreachable, or blocked for security reasons).'=>'تعذّر على هذه العقدة تحميل تلك الصفحة بأمان لمراجعتها (قد تكون غير متاحة، أو محجوبة لأسباب أمنية).','Automatic review of that page\'s content was inconclusive.'=>'كانت المراجعة التلقائية لمحتوى تلك الصفحة غير حاسمة.','Automatic review found that page\'s content isn\'t allowed to be embedded on this site.'=>'أظهرت المراجعة التلقائية أن محتوى تلك الصفحة غير مسموح بتضمينه على هذا الموقع.','Gallery overview'=>'نظرة عامة على المعرض','Feature this artwork in the gallery overview'=>'تمييز هذا العمل الفني في نظرة عامة على المعرض','Featured artworks are always chosen first when selecting one work per artist for the homepage overview.'=>'تُختار الأعمال الفنية المميزة دائمًا أولًا عند اختيار عمل واحد لكل فنان لنظرة عامة على الصفحة الرئيسية.','[Agnosis] Confirm removal of: %s'=>'[Agnosis] تأكيد إزالة: %s','[%s] We couldn\'t find that artwork or event'=>'[%s] لم نتمكن من العثور على هذا العمل الفني أو الحدث','[%s] Your artwork is now featured'=>'[%s] أصبح عملك الفني الآن مميزًا','[%s] We couldn\'t find that artwork'=>'[%s] لم نتمكن من العثور على هذا العمل الفني','We received a removal request for "%s", but couldn\'t find an artwork or event with that exact title in your account.'=>'تلقّينا طلب إزالة لـ "%s"، لكن لم نتمكن من العثور على عمل فني أو حدث بهذا العنوان تمامًا في حسابك.','We received a request to feature "%s", but couldn\'t find a published artwork with that exact title in your account.'=>'تلقّينا طلب إبراز لـ "%s"، لكن لم نتمكن من العثور على عمل فني منشور بهذا العنوان تمامًا في حسابك.','Did you mean "%s"?'=>'هل كنت تقصد "%s"؟','Yes, remove this instead'=>'نعم، أزل هذا بدلًا من ذلك','Or simply resend your original email with that exact title.'=>'أو أعد إرسال بريدك الإلكتروني الأصلي بهذا العنوان تمامًا.','Resend your original email with that exact title.'=>'أعد إرسال بريدك الإلكتروني الأصلي بهذا العنوان تمامًا.','Your current titles:'=>'العناوين الحالية لديك:','Titles are matched exactly, so a small difference in wording is enough to miss — double-check spelling, capitalization, and punctuation against the list above before resending.'=>'تتم مطابقة العناوين بدقة، لذا فإن اختلافًا بسيطًا في الصياغة يكفي لعدم التطابق — تحقّق جيدًا من الإملاء وحالة الأحرف وعلامات الترقيم مقارنةً بالقائمة أعلاه قبل إعادة الإرسال.','"%s" is now your featured artwork on the gallery overview.'=>'أصبح "%s" الآن عملك الفني المميّز في نظرة عامة على المعرض.','Any previously featured artwork has been unfeatured automatically — only one piece is featured at a time.'=>'أي عمل فني كان مميزًا سابقًا أُزيلت عنه ميزة التمييز تلقائيًا — لا يمكن تمييز سوى عمل واحد في كل مرة.','[Agnosis] Your submission is ready to review: %s'=>'[Agnosis] طلبك جاهز للمراجعة: %s','event'=>'حدث','artwork'=>'عمل فني','We received a removal request for the following %s:'=>'تلقّينا طلب إزالة للـ %s التالية:','If you want to permanently remove this %s, click the button below. This action cannot be undone.'=>'إذا كنت تريد إزالة هذا الـ %s نهائيًا، فانقر الزر أدناه. لا يمكن التراجع عن هذا الإجراء.','Yes, remove this %s'=>'نعم، أزل هذا الـ %s','If you did not request this removal, simply ignore this email — your %s will remain published.'=>'إذا لم تكن قد طلبت هذه الإزالة، فما عليك سوى تجاهل هذا البريد الإلكتروني — سيبقى الـ %s منشورًا.','This confirmation link expires in 7 days.'=>'ينتهي صلاحية رابط التأكيد هذا خلال 7 أيام.','📷 Photo enhanced automatically'=>'📷 تم تحسين الصورة تلقائيًا','We detected some photographic issues and applied AI correction to improve visibility of your artwork:'=>'رصدنا بعض المشكلات في الصورة وطبقنا تصحيحًا بالذكاء الاصطناعي لتحسين وضوح عملك الفني:','The artwork itself has not been altered — only the photograph quality was corrected.'=>'لم يتم تعديل العمل الفني نفسه — تم تصحيح جودة الصورة فقط.','📷 Photo quality score: %d/10'=>'📷 درجة جودة الصورة: %d/10','Double-check the link is correct — you can fix or remove it in the form below before publishing.'=>'تحقّق جيدًا من صحة الرابط — يمكنك إصلاحه أو إزالته في النموذج أدناه قبل النشر.','If the link was correct, its destination may simply not be from a source this site automatically embeds.'=>'إذا كان الرابط صحيحًا، فقد يكون وجهته ببساطة من مصدر لا يضمّنه هذا الموقع تلقائيًا.','🔗 A link was not included'=>'🔗 لم يتم تضمين رابط' . "\0" . '🔗 لم يتم تضمين بعض الروابط' . "\0" . '' . "\0" . '' . "\0" . '' . "\0" . '','The following couldn\'t be automatically embedded, so they were left out:'=>'تعذّر تضمين ما يلي تلقائيًا، لذلك تم استبعاده:','Its subject line didn\'t exactly match one of your existing titles. If you meant to update an existing event, "%s", resend your email with that exact title instead.'=>'لم يطابق عنوان الموضوع أحد عناوينك الحالية تمامًا. إذا كنت تقصد تحديث حدث موجود، "%s"، فأعد إرسال بريدك بهذا العنوان تمامًا بدلًا من ذلك.','Its subject line didn\'t exactly match one of your existing titles. If you meant to replace an existing artwork, "%s", resend your email with that exact title instead.'=>'لم يطابق عنوان الموضوع أحد عناوينك الحالية تمامًا. إذا كنت تقصد استبدال عمل فني موجود، "%s"، فأعد إرسال بريدك بهذا العنوان تمامًا بدلًا من ذلك.','📄 This was published as a new post'=>'📄 تم نشر هذا كتدوينة جديدة','Your submission has been processed. Here\'s what our AI curator came up with — take a look and let us know if it\'s ready to publish.'=>'تمت معالجة طلبك. إليك ما توصّل إليه قيّم الذكاء الاصطناعي لدينا — ألقِ نظرة وأخبرنا إن كان جاهزًا للنشر.','On the site: %s'=>'في الموقع: %s','In your language: %s'=>'بلغتك: %s','Looks great — Publish it'=>'يبدو رائعًا — انشره','Discard'=>'تجاهل','Want to tweak the title, text or tags before publishing?'=>'هل تريد تعديل العنوان أو النص أو الوسوم قبل النشر؟','Open your submissions page →'=>'افتح صفحة الإرسالات لديك →','The Publish and Discard links above expire in %d day. Your submission stays as a draft until you decide.'=>'تنتهي صلاحية روابط النشر والتجاهل أعلاه خلال يوم واحد. يبقى طلبك مسودة حتى تقرر.' . "\0" . 'تنتهي صلاحية روابط النشر والتجاهل أعلاه خلال %d أيام. يبقى طلبك مسودة حتى تقرر.' . "\0" . '' . "\0" . '' . "\0" . '' . "\0" . '','[%s] We couldn\'t process your submission'=>'[%s] لم نتمكن من معالجة طلبك','[%s] We couldn\'t find a photo in your email'=>'[%s] لم نتمكن من العثور على صورة في بريدك الإلكتروني','We received your email, but couldn\'t process a usable photo, audio, or video file from it — so nothing was published. This can happen when an image is pasted or inserted inline rather than added as a proper attachment, or when a file arrives in a format this server can\'t convert (for example, an iPhone photo saved in HEIC/HEIF format).'=>'تلقّينا بريدك الإلكتروني، لكننا لم نتمكن من معالجة ملف صورة أو صوت أو فيديو صالح منه — لذلك لم يُنشر شيء. قد يحدث هذا عندما تُلصق صورة أو تُدرج داخل الرسالة بدلًا من إضافتها كمرفق صحيح، أو عندما يصل ملف بصيغة لا يستطيع هذا الخادم تحويلها (مثل صورة iPhone محفوظة بصيغة HEIC/HEIF).','To resend correctly:'=>'لإعادة الإرسال بشكل صحيح:','Use your mail app\'s "Attach file" (usually a paperclip icon) rather than "Insert photo" or pasting the image directly into the message body.'=>'استخدم خيار "إرفاق ملف" في تطبيق البريد لديك (عادةً أيقونة مشبك الورق) بدلًا من "إدراج صورة" أو لصق الصورة مباشرةً في نص الرسالة.','If your photo was taken on an iPhone, try switching Settings → Camera → Formats to "Most Compatible" before taking or sending it, or use "Options" in Mail to send it as a JPEG.'=>'إذا كانت صورتك ملتقطة على iPhone، فحاول الانتقال إلى الإعدادات ← الكاميرا ← الصيغ ثم اختيار "الأكثر توافقًا" قبل التقاطها أو إرسالها، أو استخدم "خيارات" في البريد لإرسالها بصيغة JPEG.','Supported formats: JPEG, PNG, WebP, GIF, TIFF, or HEIC/HEIF for images; MP3, WAV, M4A, OGG, or FLAC for audio; MP4, MOV, AVI, WebM, OGG, or MPEG for video.'=>'الصيغ المدعومة: JPEG وPNG وWebP وGIF وTIFF أو HEIC/HEIF للصور؛ MP3 وWAV وM4A وOGG أو FLAC للصوت؛ MP4 وMOV وAVI وWebM وOGG أو MPEG للفيديو.','Once it\'s properly attached, just send it to the same address again — we\'ll pick it up automatically.'=>'بمجرد إرفاقه بشكل صحيح، أرسله مرة أخرى إلى العنوان نفسه — وسنلتقطه تلقائيًا.','The photo is too dark to show your artwork clearly. Try photographing near a large window in daylight, or use a soft lamp aimed at the work from the side.'=>'الصورة مظلمة جدًا بحيث لا تُظهر عملك الفني بوضوح. جرّب تصويرها بالقرب من نافذة كبيرة في ضوء النهار، أو استخدم مصباحًا ناعمًا موجّهًا إلى العمل من الجانب.','The photo is underexposed (too dark). Try photographing near a large window in daylight, or use a soft lamp aimed at the work from the side.'=>'الصورة ناقصة التعريض (مظلمة جدًا). جرّب تصويرها بالقرب من نافذة كبيرة في ضوء النهار، أو استخدم مصباحًا ناعمًا موجّهًا إلى العمل من الجانب.','The photo is overexposed (too bright / washed out). Avoid direct sunlight or flash pointed straight at the artwork — diffuse or indirect light works best.'=>'الصورة فائقة التعريض (ساطعة جدًا / باهتة). تجنّب ضوء الشمس المباشر أو الفلاش الموجّه مباشرة إلى العمل الفني — فالضوء المنتشر أو غير المباشر هو الأفضل.','The photo is too bright or washed out. Avoid direct sunlight or flash — diffuse light or shade gives more even tones.'=>'الصورة ساطعة جدًا أو باهتة. تجنّب ضوء الشمس المباشر أو الفلاش — فالضوء المنتشر أو الظل يعطيان تدرجات أكثر توازنًا.','There is glare or a bright reflection on the artwork. Tilt the canvas slightly or photograph at an angle to eliminate reflections from the surface.'=>'هناك وهج أو انعكاس ساطع على العمل الفني. أمل اللوحة قليلًا أو صوّر من زاوية مختلفة لإزالة الانعكاسات من السطح.','There is a reflection on the artwork surface. Tilt the canvas slightly or change your angle to eliminate it.'=>'هناك انعكاس على سطح العمل الفني. أمل اللوحة قليلًا أو غيّر زاويتك لإزالته.','The image is blurry. Rest your phone or camera on a stable surface, use the self-timer, and make sure the artwork fills most of the frame so autofocus locks on it.'=>'الصورة ضبابية. ضع هاتفك أو الكاميرا على سطح ثابت، واستخدم المؤقت الذاتي، وتأكد من أن العمل الفني يملأ معظم الإطار حتى يثبت التركيز التلقائي عليه.','The image is out of focus. Tap on the artwork on your phone screen before shooting to make sure autofocus locks on it, and hold the camera still.'=>'الصورة خارج نطاق التركيز. اضغط على العمل الفني على شاشة هاتفك قبل التصوير للتأكد من أن التركيز التلقائي يثبت عليه، وامسك الكاميرا بثبات.','There is motion blur. Hold the camera very still or use a tripod; press the shutter gently or use the self-timer to avoid shake.'=>'هناك ضبابية بسبب الحركة. أمسك الكاميرا بثبات شديد أو استخدم حاملًا ثلاثيًّا؛ واضغط زر الالتقاط برفق أو استخدم المؤقت الذاتي لتجنب الاهتزاز.','Camera shake is visible. Use a tripod or rest the camera on a flat surface and use the self-timer to avoid movement when pressing the shutter.'=>'هناك اهتزاز ظاهر في الكاميرا. استخدم حاملًا ثلاثيًّا أو ضع الكاميرا على سطح مستوٍ واستخدم المؤقت الذاتي لتجنب الحركة عند الضغط على زر الالتقاط.','The image resolution is too low. Use your phone\'s highest quality setting and make sure you\'re close enough that the artwork fills the frame.'=>'دقة الصورة منخفضة جدًا. استخدم أعلى إعداد جودة على هاتفك وتأكد من أنك قريب بما يكفي بحيث يملأ العمل الفني الإطار.','The image resolution is too low. Use your phone\'s highest quality setting and fill the frame with the artwork.'=>'دقة الصورة منخفضة جدًا. استخدم أعلى إعداد جودة على هاتفك واملأ الإطار بالعمل الفني.','The image is pixelated. Shoot from closer or use a higher resolution setting on your camera.'=>'الصورة متكسّرة البكسلات. التقطها من مسافة أقرب أو استخدم إعداد دقة أعلى على الكاميرا.','The photo has a strong color cast. Shoot under neutral daylight or use your phone\'s Auto White Balance setting for more accurate colors.'=>'للصورة صبغة لونية قوية. صوّر تحت ضوء النهار المحايد أو استخدم إعداد التوازن الأبيض التلقائي في هاتفك للحصول على ألوان أدق.','The photo looks too yellow or warm. Shoot under natural daylight or switch your phone\'s white balance to Daylight / Cloudy.'=>'تبدو الصورة مائلة إلى الأصفر أو دافئة جدًا. صوّر تحت ضوء النهار الطبيعي أو بدّل توازن الأبيض في هاتفك إلى ضوء النهار / غائم.','The photo has a cold blue tint. Move the artwork to a warmer, more natural light source or adjust your camera\'s white balance.'=>'للصورة مسحة زرقاء باردة. انقل العمل الفني إلى مصدر ضوء أكثر دفئًا وطبيعية، أو اضبط توازن الأبيض في الكاميرا.','Part of the artwork appears to be cropped out of the frame. Step back and make sure the entire work is visible before shooting.'=>'يبدو أن جزءًا من العمل الفني قد قُطع خارج الإطار. ابتعد قليلًا وتأكد من ظهور العمل كاملًا قبل التصوير.','The artwork is photographed at an angle, causing distortion. Shoot straight on, with the camera parallel to the canvas.'=>'تم تصوير العمل الفني بزاوية، مما تسبب في تشوّه. صوّره مباشرة من الأمام، مع جعل الكاميرا موازية للقماش.','The artwork looks distorted or skewed. Position your camera directly in front of the artwork, parallel to its surface.'=>'يبدو العمل الفني مشوّهًا أو مائلًا. ضع الكاميرا مباشرة أمام العمل الفني، وبشكل موازٍ لسطحه.','There is a shadow across part of the artwork. Reposition your light source or move the artwork so no shadows fall on the surface.'=>'هناك ظلّ يمر عبر جزء من العمل الفني. أعد ترتيب مصدر الضوء أو انقل العمل الفني بحيث لا تسقط ظلال على السطح.','We received your submission, but unfortunately the photo quality is too low for us to show your artwork clearly. We didn\'t publish it — but please don\'t be discouraged! A simple retake is usually all it takes.'=>'لقد استلمنا إرسالك، لكن للأسف جودة الصورة منخفضة جدًا بحيث لا نستطيع عرض عملك الفني بوضوح. لم ننشره — لكن لا تحبط! عادةً ما تكفي إعادة التقاط بسيطة فقط.','📷 Photo quality score: %d / 10'=>'📷 نتيجة جودة الصورة: %d / 10','Here\'s what our AI detected and how to fix it:'=>'إليك ما اكتشفه الذكاء الاصطناعي لدينا وكيفية إصلاحه:','The overall photo quality was too low for our AI to process the artwork clearly.'=>'كانت جودة الصورة العامة منخفضة جدًا بحيث لم يتمكن الذكاء الاصطناعي لدينا من معالجة العمل الفني بوضوح.','💡 Quick tips for a great artwork photo'=>'💡 نصائح سريعة لالتقاط صورة رائعة للعمل الفني','Use natural light — position the artwork near a window on a cloudy day for even, soft light.'=>'استخدم الضوء الطبيعي — ضع العمل الفني بالقرب من نافذة في يوم غائم للحصول على ضوء ناعم ومتساوٍ.','Shoot straight on — hold your phone parallel to the canvas to avoid perspective distortion.'=>'صوّر مباشرة من الأمام — أمسك هاتفك موازيًا للقماش لتجنّب تشوّه المنظور.','Fill the frame — let the artwork take up most of the shot; crop out distracting backgrounds.'=>'املأ الإطار — دع العمل الفني يشغل معظم اللقطة؛ واقصِ الخلفيات المشتتة.','Hold still — tap the artwork on your screen to focus, then press the shutter gently or use a self-timer.'=>'اثبت — اضغط على العمل الفني على شاشتك للتركيز، ثم اضغط زر الالتقاط برفق أو استخدم المؤقت الذاتي.','Once you have a clearer photo, just email it to the same address as before — we\'ll pick it up automatically.'=>'بمجرد أن تحصل على صورة أوضح، ما عليك سوى إرسالها بالبريد الإلكتروني إلى العنوان نفسه كما من قبل — وسنلتقطها تلقائيًا.','Your previous submission is saved in your submissions page in case you want to review what was sent.'=>'تم حفظ إرساليتك السابقة في صفحة الإرسالات الخاصة بك في حال أردت مراجعة ما تم إرساله.','View submissions →'=>'عرض الإرسالات →','Photo'=>'صورة','%s (original)'=>'%s (الأصل)','%s (poster frame)'=>'%s (إطار الملصق)','Failed to insert attachment.'=>'فشل إدراج المرفق.','Artwork or event not found.'=>'لم يتم العثور على العمل الفني أو الحدث.','%s already removed.'=>'تمت إزالة %s بالفعل.','Could not remove the %s. Please try again.'=>'تعذّر إزالة %s. يرجى المحاولة مرة أخرى.','Your %s has been removed.'=>'تمت إزالة %s الخاص بك.','A valid removal token is required.'=>'مطلوب رمز إزالة صالح.','No pending removal request found for this item.'=>'لم يتم العثور على طلب إزالة معلق لهذا العنصر.','The removal link has expired. Please send another removal request.'=>'انتهى صلاحية رابط الإزالة. يرجى إرسال طلب إزالة آخر.','Invalid removal token.'=>'رمز الإزالة غير صالح.','View it live'=>'اعرضه مباشرة','Biography published'=>'تم نشر السيرة الذاتية','Your biography has been published.'=>'تم نشر سيرتك الذاتية.','Event published'=>'تم نشر الحدث','The event has been published.'=>'تم نشر الحدث.','Artwork published'=>'تم نشر العمل الفني','The artwork has been published to the gallery.'=>'تم نشر العمل الفني في المعرض.','Submission discarded'=>'تم تجاهل الإرسال','The submission has been discarded.'=>'تم تجاهل الإرسال.','Biography removed'=>'تمت إزالة السيرة الذاتية','Your biography has been removed.'=>'تمت إزالة سيرتك الذاتية.','Event removed'=>'تمت إزالة الفعالية','The event has been removed.'=>'تمت إزالة الفعالية.','Artwork removed'=>'تمت إزالة العمل الفني','Your artwork has been removed from the gallery.'=>'تمت إزالة عملك الفني من المعرض.','This link may have already been used or may have expired. Please log in to manage your submissions.'=>'قد يكون هذا الرابط قد استُخدم بالفعل أو قد انتهت صلاحيته. يُرجى تسجيل الدخول لإدارة إرسالاتك.','Title and full text cannot be empty. Fill them back in, or use "Discard" from the original email instead.'=>'لا يمكن أن يكون العنوان والنص الكامل فارغين. أعد ملأهما، أو استخدم "تجاهل" من البريد الإلكتروني الأصلي بدلًا من ذلك.','The full text cannot be empty. Fill it back in, or use "Discard" from the original email instead.'=>'لا يمكن أن يكون النص الكامل فارغًا. أعد ملأه، أو استخدم "تجاهل" من البريد الإلكتروني الأصلي بدلًا من ذلك.','Portfolio link'=>'رابط الملف التعريفي','Social link %d (optional)'=>'رابط اجتماعي %d (اختياري)','Hour'=>'الساعة','Location'=>'الموقع','Address'=>'العنوان','Timezone'=>'المنطقة الزمنية','Other'=>'أخرى','— Not set —'=>'— غير مضبوط —','Discard this submission?'=>'هل تريد تجاهل هذا الإرسال؟','This will permanently discard the submission — it will not be published.'=>'سيؤدي هذا إلى تجاهل الإرسال نهائيًا — ولن يتم نشره.','Yes, discard it'=>'نعم، تجاهله','Remove this artwork?'=>'هل تريد إزالة هذا العمل الفني؟','This will remove the published artwork from the gallery.'=>'سيؤدي هذا إلى إزالة العمل الفني المنشور من المعرض.','Yes, remove it'=>'نعم، أزِله','Title'=>'العنوان','Short description'=>'وصف قصير','Full text'=>'النص الكامل','Publish this %s?'=>'هل تريد نشر هذا %s؟','Make any final changes below, or leave everything as-is to publish exactly what was drafted.'=>'أجرِ أي تعديلات نهائية أدناه، أو اترك كل شيء كما هو لنشر ما تمّت صياغته تمامًا.','Publish it'=>'انشره','biography'=>'سيرة ذاتية','Submission not found.'=>'لم يتم العثور على الإرسال.','This submission is not awaiting review.'=>'هذا الإرسال ليس بانتظار المراجعة.','The original published item could not be found.'=>'تعذّر العثور على العنصر المنشور الأصلي.','You do not have permission to review this submission.'=>'ليس لديك إذن لمراجعة هذا الإرسال.','Review link not found or already used.'=>'لم يتم العثور على رابط المراجعة أو تم استخدامه بالفعل.','Invalid review token.'=>'رمز المراجعة غير صالح.','This review link has expired. Please log in to manage your submissions.'=>'انتهت صلاحية رابط المراجعة هذا. يُرجى تسجيل الدخول لإدارة إرسالاتك.','No submissions awaiting review.'=>'لا توجد إرسالات بانتظار المراجعة.','Make changes'=>'إجراء تغييرات','One-line description'=>'وصف بسطر واحد','Description'=>'الوصف','Tags (comma-separated)'=>'الوسوم (مفصولة بفواصل)','Save &amp; Publish'=>'حفظ و&amp;نشر','Publishing…'=>'جارٍ النشر…','Published ✓'=>'تم النشر ✓','Something went wrong.'=>'حدث خطأ ما.','Could not connect. Please try again.'=>'تعذّر الاتصال. يُرجى المحاولة مرة أخرى.','Discard this submission? This cannot be undone.'=>'هل تريد تجاهل هذا الإرسال؟ لا يمكن التراجع عن هذا الإجراء.','Discarding…'=>'جارٍ الحذف…','Discarded.'=>'تم الحذف.','Saving and publishing…'=>'جارٍ الحفظ والنشر…','Log in to view your submissions'=>'سجّل الدخول لعرض عمليات الإرسال الخاصة بك','Username or email address'=>'اسم المستخدم أو عنوان البريد الإلكتروني','Password'=>'كلمة المرور','Log in'=>'سجّل الدخول','Remember me'=>'تذكرني','Forgot your password?'=>'هل نسيت كلمة المرور؟','Book'=>'كتاب','Person'=>'شخص','Calendar'=>'تقويم','Pin'=>'دبوس','Baseline (default)'=>'الأساس (الافتراضي)','Top'=>'أعلى','Middle'=>'الوسط','Bottom'=>'أسفل','Icon settings'=>'إعدادات الأيقونة','Biography icon'=>'أيقونة السيرة الذاتية','Events icon'=>'أيقونة الفعاليات','Icon size'=>'حجم الأيقونة','Icon vertical align'=>'المحاذاة العمودية للأيقونة','Icon-only links have no text baseline of their own — use this if they sit too high or low next to the artist name once Icon size is changed from the default.'=>'الروابط التي تقتصر على الأيقونة لا تملك خط أساس نصيًا خاصًا بها — استخدم هذا إذا بدت أعلى أو أسفل من اللازم بجانب اسم الفنان بعد تغيير حجم الأيقونة عن القيمة الافتراضية.','Icon color'=>'لون الأيقونة','Leave unset to match the block’s own text color.'=>'اتركه غير محدد ليتطابق مع لون نص الكتلة نفسه.','Artist Name'=>'اسم الفنان','Envelope'=>'ظرف','Speech bubble'=>'فقاعة كلام','Contact'=>'اتصال','Link settings'=>'إعدادات الرابط','Link type'=>'نوع الرابط','Icon'=>'أيقونة','Biography Icon'=>'أيقونة السيرة الذاتية','Icon-only link to the artist’s biography.'=>'رابط بأيقونة فقط إلى السيرة الذاتية للفنان.','Events Icon'=>'أيقونة الفعاليات','Icon-only link to the artist’s events archive.'=>'رابط بأيقونة فقط إلى أرشيف فعاليات الفنان.','Contact Icon'=>'أيقونة الاتصال','Opens a popover with a form to message the artist directly. Hidden automatically if the artist has turned contact messages off.'=>'يفتح نافذة منبثقة تحتوي على نموذج لمراسلة الفنان مباشرةً. يُخفى تلقائيًا إذا كان الفنان قد أوقف رسائل الاتصال.','Artist Contact Form'=>'نموذج اتصال الفنان','Lets a visitor message the current artist subdomain’s artist. Content is rendered live on the frontend, for the artist currently being viewed.'=>'يتيح للزائر مراسلة فنان النطاق الفرعي الحالي. يُعرض المحتوى مباشرةً على الواجهة الأمامية، للفنان الذي تتم مشاهدته حاليًا.','Gallery settings'=>'إعدادات المعرض','Columns'=>'الأعمدة','✦ Agnosis Gallery Overview — rendered on the server'=>'✦ نظرة عامة على معرض أغنوسيس — معروض على الخادم','columns · proportional · random daily order'=>'أعمدة · متناسب · ترتيب يومي عشوائي','Join Agnosis'=>'انضم إلى أغنوسيس','Public application form for new artists. Submits name, email, bio, portfolio URL and a personal statement to the community for review. Content is rendered live on the frontend.'=>'نموذج طلب عام للفنانين الجدد. يرسل الاسم والبريد الإلكتروني والسيرة الذاتية ورابط الملف الشخصي وبيانًا شخصيًا إلى المجتمع للمراجعة. يُعرض المحتوى مباشرةً على الواجهة الأمامية.','Place this block on your /join/ page or in a Site Editor page template assigned to that page.'=>'ضع هذه الكتلة في صفحة /join/ الخاصة بك أو في قالب صفحة ضمن محرر الموقع مخصص لتلك الصفحة.','Bell'=>'جرس','Star'=>'نجمة','Lightning bolt'=>'صاعقة كهربائية','Newsletter Popover — opens the signup form'=>'منبثق النشرة البريدية — يفتح نموذج الاشتراك','Newsletter settings'=>'إعدادات النشرة البريدية','Trigger icon'=>'أيقونة التشغيل','Pick something that won’t blend in with icons already sitting next to it (e.g. Social Share).'=>'اختر شيئًا لا يندمج مع الأيقونات الموجودة بجانبه (مثلًا: مشاركة اجتماعية).','Newsletter Signup'=>'اشتراك النشرة البريدية','Email signup form for the public newsletter. A confirmation email is sent before anyone is added to the send list (double opt-in). Content is rendered live on the frontend.'=>'نموذج اشتراك بالبريد الإلكتروني للنشرة البريدية العامة. يتم إرسال رسالة تأكيد بالبريد الإلكتروني قبل إضافة أي شخص إلى قائمة الإرسال (تأكيد مزدوج). يتم عرض المحتوى مباشرة على الواجهة الأمامية.','block titleArtist Breadcrumb'=>'فتات الفنان','block descriptionSmall line identifying the artist whose subdomain is currently being viewed. Renders nothing on the main Agnosis site.'=>'سطر صغير يعرّف بالفنان الذي يتم عرض نطاقه الفرعي حاليًا. لا يعرض شيئًا على الموقع الرئيسي لـ Agnosis.','block keywordartist'=>'فنان','block keywordbreadcrumb'=>'فتات الخبز','block keywordsubdomain'=>'النطاق الفرعي','block keywordagnosis'=>'أغنوسِس','block titleArtist Name Link'=>'رابط اسم الفنان','block descriptionLinks to the current artist\'s own subdomain home. Renders nothing off an artist subdomain.'=>'يرتبط بصفحة الرئيسية للنطاق الفرعي الخاص بالفنان الحالي. لا يعرض شيئًا خارج نطاق فرعي لفنان.','block titleBreadcrumb Icon Link'=>'رابط أيقونة فتات الخبز','block descriptionA single icon-only link (Biography, Events, or a Contact popover) to/about the current artist. Renders nothing if there\'s nothing to show (no biography/events yet, or the artist has turned contact off), or off an artist subdomain.'=>'رابط واحد بأيقونة فقط (السيرة الذاتية، الفعاليات، أو نافذة منبثقة للتواصل) متعلق بالفنان الحالي. لا يعرض شيئًا إذا لم يكن هناك ما يُعرض (لا توجد سيرة ذاتية/فعاليات بعد، أو أن الفنان أوقف التواصل)، أو خارج نطاق فرعي لفنان.','block keywordbiography'=>'السيرة الذاتية','block keywordevents'=>'الفعاليات','block keywordcontact'=>'التواصل','block keywordicon'=>'أيقونة','block titleArtist Contact Form'=>'نموذج تواصل الفنان','block descriptionContact form letting a visitor message the current artist subdomain\'s artist. Submits to a per-artist REST endpoint; the message is moderated, translated into the artist\'s own language, and emailed to them.'=>'نموذج تواصل يتيح للزائر إرسال رسالة إلى فنان النطاق الفرعي الحالي. يُرسل إلى نقطة نهاية REST خاصة بكل فنان؛ وتُراجع الرسالة وتُترجم إلى لغة الفنان الخاصة، ثم تُرسل إليه بالبريد الإلكتروني.','block keywordmessage'=>'رسالة','block keywordemail'=>'بريد إلكتروني','block titleAgnosis Gallery Overview'=>'نظرة عامة على معرض Agnosis','block descriptionProportional, randomised artwork grid across all artists. Shows featured artworks first, respects per-artist budget, supports medium filtering and pagination.'=>'شبكة أعمال فنية متناسبة وعشوائية عبر جميع الفنانين. تعرض الأعمال المميزة أولًا، وتراعي الميزانية الخاصة بكل فنان، وتدعم التصفية حسب الوسيط والترقيم الصفحي.','block keywordgallery'=>'معرض','block keywordartwork'=>'عمل فني','block keywordartists'=>'الفنانون','block keywordoverview'=>'نظرة عامة','block titleJoin Agnosis'=>'انضم إلى Agnosis','block descriptionPublic application form for artists who want to join the Agnosis network. Submits to the admission REST endpoint. Place this on your /join/ page.'=>'نموذج طلب عام للفنانين الذين يرغبون في الانضمام إلى شبكة Agnosis. يُرسل إلى نقطة نهاية القبول REST. ضع هذا في صفحة /join/ الخاصة بك.','block keywordjoin'=>'انضم','block keywordapply'=>'تقدّم','block keywordapplication'=>'طلب','block keywordadmission'=>'القبول','block titleNewsletter Popover'=>'منبثق النشرة البريدية','block descriptionIcon button that opens a full-viewport popover containing the newsletter signup form. Self-contained — drop it directly into a header or footer template part; renders nothing when the public newsletter is disabled (Settings → Newsletter).'=>'زر بأيقونة يفتح نافذة منبثقة بملء الشاشة تحتوي على نموذج الاشتراك في النشرة البريدية. مستقل بذاته — ضعه مباشرةً في جزء قالب الرأس أو التذييل؛ لا يعرض شيئًا عندما تكون النشرة البريدية العامة معطلة (الإعدادات → النشرة البريدية).','block keywordnewsletter'=>'النشرة البريدية','block keywordsubscribe'=>'اشترك','block keywordpopover'=>'منبثق','block keywordfooter'=>'التذييل','block titleNewsletter Signup'=>'اشتراك النشرة البريدية','block descriptionEmail signup form for the public newsletter (double opt-in). Submits to the newsletter subscribe REST endpoint.'=>'نموذج اشتراك بالبريد الإلكتروني للنشرة البريدية العامة (تأكيد مزدوج). يُرسل إلى نقطة نهاية REST الخاصة بالاشتراك في النشرة البريدية.','block keywordsignup'=>'اشتراك','block titleMy Submissions'=>'إرسالاتي','block descriptionLists the logged-in artist\'s pending artwork submissions for review and approval. Place this on your /my-submissions/ page or in a Site Editor template.'=>'يعرض الأعمال الفنية المرسلة قيد الانتظار للفنان المسجّل الدخول للمراجعة والموافقة. ضع هذا في صفحة /my-submissions/ الخاصة بك أو في قالب ضمن محرر الموقع.','block keywordsubmissions'=>'المرسلات','block keywordreview'=>'مراجعة']];